        {loaded && topics.length === 0 && (
          <div className="glass rise p-10 text-center">
            <div className="mx-auto mb-5 flex h-16 w-16 items-center justify-center rounded-full bg-gradient-to-br from-[#ff7a5c] to-[#f5b95f] text-2xl">

            </div>
            <h2 className="mb-2 text-lg font-bold">No topics yet</h2>
            <p className="mb-5 text-muted">Add your first learning to generate topic blogs.</p>
            <Link href="/add" className="btn-primary">Add a learning</Link>
          </div>
        )}

        {/* No results */}
        {loaded && topics.length > 0 && filtered.length === 0 && (
          <div className="glass rise p-8 text-center">
            <p className="text-muted">No topics match your search.</p>
            <button
              onClick={() => { setSearch(""); setCategoryFilter(null); }}
              className="mt-4 text-sm text-[#f5b95f] underline underline-offset-2"
            >
              Clear filters
            </button>
          </div>
        )}

        {/* Topic grid */}
        {filtered.length > 0 && (
          <div className="rise grid gap-4 sm:grid-cols-2">
            {filtered.map((topic) => {
              const color = categoryColor(topic.category);
              return (
                <Link
                  key={topic.id}
                  href={`/blogs/${topic.id}`}
                  className="glass glass-hover group relative overflow-hidden rounded-[1.5rem] p-5 transition-all"
                >
                  {/* Ambient glow */}
                  <div
                    className="absolute -right-8 -top-8 h-24 w-24 rounded-full opacity-20 blur-2xl transition-opacity group-hover:opacity-30"
                    style={{ background: color }}
                    aria-hidden
                  />

                  {/* Category badge */}
                  <span
                    className="mb-3 inline-block rounded-full px-2.5 py-0.5 text-[11px] font-semibold"
                    style={{ background: `${color}20`, color }}
                  >
                    {topic.category}
                  </span>

                  {/* Title */}
                  <h2
                    className="mb-2 text-base font-bold leading-snug transition-colors group-hover:text-white"
                    style={{ color: "rgba(255,252,245,0.92)" }}
                  >
                    {topic.name}
                  </h2>

                  {/* Summary */}
                  {topic.summary && (
                    <p className="mb-4 line-clamp-2 text-sm leading-relaxed text-faint">
                      {topic.summary}
                    </p>
                  )}

                  {/* Footer — review count */}
                  <div className="flex items-center gap-3 text-xs text-faint">
                    <span>{topic.review_count} review{topic.review_count === 1 ? "" : "s"}</span>
                    <span
                      aria-hidden
                      className="ml-auto shrink-0 opacity-0 transition-all group-hover:translate-x-0.5 group-hover:opacity-100"
                      style={{ color }}
                    >
                      →
                    </span>
                  </div>
                </Link>
              );
            })}
          </div>
        )}

        {/* Topic count */}
        {filtered.length > 0 && (
          <p className="mt-6 text-center text-xs text-faint">
            {filtered.length} topic{filtered.length !== 1 ? "s" : ""}
            {(search || categoryFilter) && ` · filtered from ${topics.length}`}
          </p>
        )}
      </main>

      {/* Write-to-us modal — request a dedicated story */}
      {writeOpen && (
        <div
          className="fixed inset-0 z-[120] flex items-center justify-center p-4"
          onClick={() => setWriteOpen(false)}
        >
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" aria-hidden />
          <div
            className="glass relative w-full max-w-lg overflow-hidden rounded-[1.75rem] p-6 sm:p-7"
            onClick={(e) => e.stopPropagation()}
          >
            <div
              className="pointer-events-none absolute -right-16 -top-16 h-48 w-48 rounded-full opacity-[0.14] blur-3xl"
              style={{ background: "linear-gradient(135deg,#ff7a5c,#f5b95f)" }}
              aria-hidden
            />
            <button
              onClick={() => setWriteOpen(false)}
              className="absolute right-4 top-4 flex h-8 w-8 items-center justify-center rounded-full bg-white/[0.06] text-faint transition-colors hover:bg-white/[0.12] hover:text-white"
              aria-label="Close"
            >
              ✕
            </button>

            <div className="mb-4 flex items-center gap-3">
              <span className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-[#f5b95f]/[0.14] text-lg">
                ✍️
              </span>
              <div>
                <p className="micro !text-[#f5b95f]">Contribute a series</p>
                <h2 className="text-lg font-bold text-white/95">Want a dedicated story?</h2>
              </div>
            </div>

            <p className="mb-4 text-sm leading-relaxed text-muted">
              We turn well-structured material into linear, chapter-by-chapter stories others can
              read and learn from. If you have expertise or a resource worth sharing, send it our way.
            </p>

            <div className="mb-5 rounded-2xl border border-white/[0.07] bg-white/[0.02] p-4">
              <p className="micro mb-2.5 !text-faint">What to include</p>
              <ul className="space-y-2 text-sm text-white/80">
                {[
                  "A clear subject and the audience it's for (beginner, interview prep, etc.).",
                  "A proper document or a public link for reference — Google Doc, PDF, article, or a repo.",
                  "The rough structure or table of contents, if you already have one.",
                  "Any must-cover examples, cases, or diagrams you'd like included.",
                ].map((t, i) => (
                  <li key={i} className="flex gap-2.5">
                    <span className="mt-[0.5em] h-1 w-1 shrink-0 rounded-full bg-[#f5b95f]/70" />
                    <span className="flex-1 leading-relaxed">{t}</span>
                  </li>
                ))}
              </ul>
            </div>

            <div className="flex flex-wrap gap-3">
              <a
                href={`mailto:sanyamgupta2307@gmail.com?subject=${encodeURIComponent(
                  "Knovis — dedicated story request"
                )}&body=${encodeURIComponent(
                  "Subject / topic:\nAudience:\nReference document or link:\nRough structure:\nMust-cover examples or cases:\n"
                )}`}
                className="btn-primary"
              >
                Write to us
              </a>
              <button onClick={() => setWriteOpen(false)} className="btn-ghost">
                Maybe later
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

function ChevronDownIcon({ className = "h-4 w-4" }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M6 9l6 6 6-6" />
    </svg>
  );
}

function SearchIcon({ className = "h-4 w-4" }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
      <circle cx="11" cy="11" r="7" />
      <path d="M20 20l-3.5-3.5" />
    </svg>
  );
}

function ArrowRightIcon({ className = "h-4 w-4" }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M5 12h14M12 5l7 7-7 7" />
    </svg>
  );
}

/** Tiny radial progress ring for inline use on series cards. */
function MiniRing({ size, stroke, pct, color }: { size: number; stroke: number; pct: number; color: string }) {
  const r = (size - stroke) / 2;
  const c = 2 * Math.PI * r;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="-rotate-90">
      <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="rgba(255,252,245,0.08)" strokeWidth={stroke} />
      <circle
        cx={size / 2}
        cy={size / 2}
        r={r}
        fill="none"
        stroke={color}
        strokeWidth={stroke}
        strokeLinecap="round"
        strokeDasharray={c}
        strokeDashoffset={c * (1 - pct / 100)}
        style={{ filter: `drop-shadow(0 0 3px ${color}66)` }}
      />
    </svg>
  );
}

"use client";

import Link from "next/link";
import { useCallback, useEffect, useMemo, useState } from "react";
import Nav from "@/components/Nav";
import BrainScene from "@/components/BrainScene";
import { getLinks, getTopics } from "@/lib/data";
import {
  getAllStorySections,
  getStartedStories,
  storySectionHref,
  type StorySection,
  type UserStory,
} from "@/lib/stories";
import type { Topic, TopicLink } from "@/lib/types";
import { CATEGORY_COLORS, categoryColor } from "@/lib/types";

/** Display titles for learnable story series (extend as series are added). */
const SERIES_TITLES: Record<string, string> = {
  "competition-act": "The Competition Code",
  "dsa": "The Pattern Atlas",
  "sql": "The Query Playbook",
};

export default function BrainPage() {
  const [topics, setTopics] = useState<Topic[]>([]);
  const [links, setLinks] = useState<TopicLink[]>([]);
  const [query, setQuery] = useState("");
  // the walked trail of topics — each step is (ideally) linked to the previous
  const [path, setPath] = useState<string[]>([]);
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);
  const [searchFocused, setSearchFocused] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [stories, setStories] = useState<UserStory[]>([]);
  const [storySections, setStorySections] = useState<StorySection[]>([]);
  const [focusSeries, setFocusSeries] = useState<string | null>(null);

  useEffect(() => {
    Promise.all([getTopics(), getLinks(), getStartedStories(), getAllStorySections()]).then(
      ([t, l, s, ss]) => {
        setTopics(t);
        setLinks(l);
        setStories(s);
        setStorySections(ss);
        setLoaded(true);
      }
    );
  }, []);

  const byId = useMemo(() => new Map(topics.map((t) => [t.id, t])), [topics]);

  // topic_id → its story section (for "read the full topic" hrefs + focus set)
  const storyByTopic = useMemo(
    () => new Map(storySections.map((s) => [s.topic_id, s])),
    [storySections]
  );

  // story-focus: recolour this story's nodes, dim the rest
  const highlight = useMemo(() => {
    if (!focusSeries) return null;
    const ids = new Set(
      storySections.filter((s) => s.series_slug === focusSeries).map((s) => s.topic_id)
    );
    if (!ids.size) return null;
    const color = stories.find((s) => s.series_slug === focusSeries)?.color ?? "#5ba4cf";
    return { topicIds: ids, color };
  }, [focusSeries, storySections, stories]);

  // give every topic belonging to a story its story's colour as a baseline
  const topicColors = useMemo(() => {
    const map = new Map<string, string>();
    for (const sec of storySections) {
      const color = stories.find((s) => s.series_slug === sec.series_slug)?.color;
      if (color) map.set(sec.topic_id, color);
    }
    return map;
  }, [storySections, stories]);

  // where "read the full topic" points: the static section blog for story
  // topics, the auto-generated topic blog otherwise
  const blogHref = useCallback(
    (t: Topic) => {
      const sec = storyByTopic.get(t.id);
      return sec ? storySectionHref(sec) : `/blogs/${t.id}`;
    },
    [storyByTopic]
  );

  const isLinked = useCallback(
    (a: string, b: string) =>
      links.some(
        (l) => (l.source === a && l.target === b) || (l.source === b && l.target === a)
      ),
    [links]
  );

  // Walk to a topic: jump back if already visited, extend the path if it's
  // connected to where we are, otherwise begin a fresh trail.
  const navigateTo = useCallback(
    (id: string) => {
      setPath((prev) => {
        const idx = prev.indexOf(id);
        if (idx !== -1) return prev.slice(0, idx + 1);
        const tail = prev[prev.length - 1];
        if (!tail || isLinked(tail, id)) return [...prev, id];
        return [id];
      });
    },
    [isLinked]
  );

  // Esc backs out of the dive-inside view (same as the close button)
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== "Escape") return;
      // leave Esc alone while typing (search box handles its own escape)
      const el = document.activeElement;
      if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) return;
      setPath((prev) => (prev.length ? [] : prev));
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  const visibleTopics = useMemo(
    () => (categoryFilter ? topics.filter((t) => t.category === categoryFilter) : topics),
    [topics, categoryFilter]
  );

  const results = useMemo(() => {
    if (!query.trim()) return [];
    const q = query.toLowerCase();
    return topics
      .filter((t) => t.name.toLowerCase().includes(q) || t.summary?.toLowerCase().includes(q))
      .slice(0, 8);
  }, [query, topics]);

  const current = path.length ? byId.get(path[path.length - 1]) ?? null : null;
  const currentConnections = useMemo(() => {
    if (!current) return [];
    const cur = current;
    return links
      .filter((l) => l.source === cur.id || l.target === cur.id)
      .flatMap((l) => {
        const topic = byId.get(l.source === cur.id ? l.target : l.source);
        return topic ? [{ topic, reason: l.reason }] : [];
      });
  }, [current, links, byId]);

  // categories are derived live from whatever the user has actually added
  const categories = useMemo(() => {
    const counts = new Map<string, number>();
    for (const t of topics) counts.set(t.category, (counts.get(t.category) ?? 0) + 1);
    return Array.from(counts.entries()).sort((a, b) => b[1] - a[1]);
  }, [topics]);

  // trail rendered newest-first (current card on top, history stacked beneath)
  const trail = useMemo(() => [...path].reverse(), [path]);

  return (
    <div className="flex h-screen flex-col overflow-hidden">
      <Nav />
      <main className="relative flex-1">
        {/* Brain fills the page */}
        <div className="absolute inset-0" data-tour="brain-canvas">
          {loaded && topics.length > 0 && (
            <BrainScene
              topics={visibleTopics}
              links={links}
              path={path}
              onSelect={(id) => id && navigateTo(id)}
              highlight={highlight}
              topicColors={topicColors}
            />
          )}
          {loaded && topics.length === 0 && (
            <div className="flex h-full items-center justify-center">
              <div className="glass max-w-sm p-10 text-center">
                <h2 className="mb-2 text-lg font-bold">Your brain is empty</h2>
                <p className="mb-4 text-sm text-muted">
                  Log your first conversation and watch topics light up here.
                </p>
                <Link href="/add" className="btn-primary">Add a learning</Link>
              </div>
            </div>
          )}
        </div>

        {/* Search overlay */}
        <div className="pointer-events-none absolute inset-x-0 top-0 z-10 p-4 sm:p-6">
          <div className="pointer-events-auto mx-auto max-w-xl">
            <div className="relative" data-tour="brain-search">
              <SearchIcon className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-faint" />
              <input
                className="input !rounded-full pl-11"
                style={{ background: "rgba(18,15,20,0.7)", backdropFilter: "blur(20px)", boxShadow: "0 18px 50px rgba(0,0,0,0.45)" }}
                placeholder="Search your brain…"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onFocus={() => setSearchFocused(true)}
                onBlur={() => setTimeout(() => setSearchFocused(false), 150)}
              />
              {(results.length > 0 || (searchFocused && !query.trim() && categories.length > 0)) && (
                <div className="overlay-panel absolute inset-x-0 top-full mt-2 overflow-hidden !rounded-[1.5rem] p-1.5">
                  {results.map((t) => (
                    <button
                      key={t.id}
                      className="flex w-full items-center gap-3 rounded-full px-4 py-2.5 text-left transition-colors hover:bg-white/[0.06]"
                      onClick={() => {
                        navigateTo(t.id);
                        setQuery("");
                        setCategoryFilter(null);
                      }}
                    >
                      <span
                        className="h-2 w-2 shrink-0 rounded-full"
                        style={{ background: topicColors.get(t.id) ?? categoryColor(t.category) }}
                      />
                      <span className="min-w-0 flex-1 truncate text-sm font-medium">{t.name}</span>
                      <span className="text-xs text-faint">{t.mastery}%</span>
                    </button>
                  ))}
                  {/* your areas of the brain — built from the topics you've added */}
                  {searchFocused && !query.trim() && (
                    <div className="flex flex-wrap gap-1.5 p-2.5">
                      {categories.map(([c, count]) => (
                        <button
                          key={c}
                          onClick={() => setCategoryFilter(categoryFilter === c ? null : c)}
                          className="rounded-full px-3 py-1.5 text-[11px] font-medium transition-all"
                          style={{
                            background: categoryFilter === c ? `${CATEGORY_COLORS[c] ?? "#a8a29e"}2e` : "rgba(255,252,245,0.05)",
                            color: CATEGORY_COLORS[c] ?? "#a8a29e",
                          }}
                        >
                          {c} · {count}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* story focus — light up one learnable story, dim the rest */}
            {stories.length > 0 && (
              <div className="pointer-events-auto mt-3 flex flex-wrap justify-center gap-2">
                {stories.map((s) => {
                  const active = focusSeries === s.series_slug;
                  return (
                    <button
                      key={s.series_slug}
                      onClick={() => setFocusSeries(active ? null : s.series_slug)}
                      className="flex items-center gap-1.5 rounded-full px-3.5 py-1.5 text-[11px] font-semibold backdrop-blur-xl transition-all"
                      style={{
                        background: active ? `${s.color}2e` : "rgba(18,15,20,0.6)",
                        color: s.color,
                        boxShadow: "0 8px 24px rgba(0,0,0,0.35)",
                      }}
                    >
                      <span className="h-2 w-2 rounded-full" style={{ background: s.color }} />
                      {SERIES_TITLES[s.series_slug] ?? s.series_slug}
                      {active && <span className="opacity-70">✕</span>}
                    </button>
                  );
                })}
              </div>
            )}

            {/* active filter chip — the only thing that stays over the brain */}
            {categoryFilter && (
              <div className="mt-3 flex justify-center">
                <button
                  onClick={() => setCategoryFilter(null)}
                  className="flex items-center gap-1.5 rounded-full px-3.5 py-1.5 text-[11px] font-semibold backdrop-blur-xl"
                  style={{
                    background: `${CATEGORY_COLORS[categoryFilter] ?? "#a8a29e"}22`,
                    color: CATEGORY_COLORS[categoryFilter] ?? "#a8a29e",
                  }}
                >
                  {categoryFilter} <span className="opacity-70">✕</span>
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Path panel — a stack of the topics you've walked through */}
        {current && (
          <aside className="absolute bottom-24 left-4 right-4 z-10 max-h-[52%] overflow-y-auto md:bottom-auto md:left-auto md:right-6 md:top-24 md:max-h-[72%] md:w-96">
            {trail.map((id, i) => {
              const t = byId.get(id);
              if (!t) return null;
              const isCurrent = i === 0;
              // original index in the forward path (for jump-back)
              const originalIndex = path.length - 1 - i;
              const color = topicColors.get(t.id) ?? categoryColor(t.category);

              if (!isCurrent) {
                // a walked-past step — compact, click to return
                return (
                  <div key={id}>
                    <PathConnector />
                    <button
                      onClick={() => setPath(path.slice(0, originalIndex + 1))}
                      className="overlay-panel flex w-full items-center gap-3 !rounded-2xl px-4 py-3 text-left opacity-70 transition-opacity hover:opacity-100"
                    >
                      <span className="h-2 w-2 shrink-0 rounded-full" style={{ background: color }} />
                      <span className="min-w-0 flex-1 truncate text-sm font-medium">{t.name}</span>
                      <span className="micro shrink-0">step {originalIndex + 1}</span>
                    </button>
                  </div>
                );
              }

              // the current topic — expanded card
              return (
                <div key={id}>
                  {trail.length > 1 && <PathConnector />}
                  <div className="overlay-panel p-6">
                    <div className="mb-3 flex items-start justify-between gap-3">
                      <div>
                        <span
                          className="mb-1.5 inline-block rounded-full px-2.5 py-0.5 text-[11px] font-semibold"
                          style={{ background: `${color}20`, color }}
                        >
                          {t.category}
                        </span>
                        <Link
                          href={blogHref(t)}
                          target="_blank"
                          rel="noopener"
                          className="text-lg font-bold leading-snug transition-colors hover:text-[#f5b95f]"
                        >
                          {t.name}
                        </Link>
                      </div>
                      <button
                        onClick={() => setPath([])}
                        className="rounded-full p-1.5 text-faint hover:bg-white/[0.06] hover:text-white"
                        aria-label="Close"
                      >
                        ✕
                      </button>
                    </div>



                    <p className="mb-3 line-clamp-2 text-sm leading-relaxed text-white/80">{t.summary}</p>

                    <Link
                      href={blogHref(t)}
                      target="_blank"
                      rel="noopener"
                      className="group mb-5 inline-flex items-center gap-1.5 text-xs font-semibold"
                      style={{ color: color }}
                    >
                      Read the full topic
                      <span className="transition-transform group-hover:translate-x-0.5">↗</span>
                    </Link>

                    {t.key_points?.length > 0 && (
                      <>
                        <h3 className="micro mb-2">Key points</h3>
                        <ul className="mb-4 space-y-1.5">
                          {t.key_points.map((k, j) => (
                            <li key={j} className="flex gap-2 text-sm text-muted">
                              <span className="text-[#f5b95f]">•</span>
                              {k}
                            </li>
                          ))}
                        </ul>
                      </>
                    )}

                    {currentConnections.length > 0 && (
                      <>
                        <h3 className="micro mb-2">Follow a connection</h3>
                        <ul className="space-y-2">
                          {currentConnections.map((c, j) => {
                            const visited = path.includes(c.topic.id);
                            return (
                              <li key={j}>
                                <button
                                  onClick={() => navigateTo(c.topic.id)}
                                  className="row-soft flex w-full items-start gap-2.5 px-3.5 py-2.5 text-left"
                                >
                                  <span
                                    className="mt-1.5 h-1.5 w-1.5 shrink-0 rounded-full"
                                    style={{ background: topicColors.get(c.topic.id) ?? categoryColor(c.topic.category) }}
                                  />
                                  <span className="min-w-0 flex-1">
                                    <span
                                      className="text-sm font-medium"
                                      style={{ color: topicColors.get(c.topic.id) ?? categoryColor(c.topic.category) }}
                                    >
                                      {c.topic.name}
                                    </span>
                                    {visited && <span className="micro ml-2">visited</span>}
                                    {c.reason && (
                                      <span className="mt-0.5 block text-xs leading-snug text-faint">
                                        {c.reason}
                                      </span>
                                    )}
                                  </span>
                                </button>
                              </li>
                            );
                          })}
                        </ul>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </aside>
        )}

        {/* Legend / hint */}
        {!current && (
          <div className="pointer-events-none absolute bottom-24 left-1/2 z-0 -translate-x-1/2 md:bottom-6">
            <p className="micro rounded-full bg-[#100e14]/60 px-4 py-2 backdrop-blur-xl">
              hover to name · click a glow to dive inside · follow links to walk a path
            </p>
          </div>
        )}
      </main>
    </div>
  );
}

/** A small vertical link between stacked path cards. */
function PathConnector() {
  return (
    <div className="flex justify-center py-1.5" aria-hidden>
      <span className="block h-4 w-px bg-gradient-to-b from-transparent via-white/25 to-white/25" />
    </div>
  );
}

function SearchIcon({ className = "h-4 w-4" }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
      <circle cx="11" cy="11" r="7" />
      <path d="M20 20l-3.5-3.5" />
    </svg>
  );
}

"use client";

import Link from "next/link";
import { useCallback, useEffect, useMemo, useState } from "react";
import Nav from "@/components/Nav";
import BrainScene from "@/components/BrainScene";
import { getLinks, getTopics } from "@/lib/data";
import {
  getAllStorySections,
  getStartedStories,
  storySectionHref,
  type StorySection,
  type UserStory,
} from "@/lib/stories";
import type { Topic, TopicLink } from "@/lib/types";
import { CATEGORY_COLORS, categoryColor } from "@/lib/types";

/** Display titles for learnable story series (extend as series are added). */
const SERIES_TITLES: Record<string, string> = {
  "competition-act": "The Competition Code",
  "dsa": "The Pattern Atlas",
  "sql": "The Query Playbook",
};

export default function BrainPage() {
  const [topics, setTopics] = useState<Topic[]>([]);
  const [links, setLinks] = useState<TopicLink[]>([]);
  const [query, setQuery] = useState("");
  // the walked trail of topics — each step is (ideally) linked to the previous
  const [path, setPath] = useState<string[]>([]);
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);
  const [searchFocused, setSearchFocused] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [stories, setStories] = useState<UserStory[]>([]);
  const [storySections, setStorySections] = useState<StorySection[]>([]);
  const [focusSeries, setFocusSeries] = useState<string | null>(null);

  useEffect(() => {
    Promise.all([getTopics(), getLinks(), getStartedStories(), getAllStorySections()]).then(
      ([t, l, s, ss]) => {
        setTopics(t);
        setLinks(l);
        setStories(s);
        setStorySections(ss);
        setLoaded(true);
      }
    );
  }, []);

  const byId = useMemo(() => new Map(topics.map((t) => [t.id, t])), [topics]);

  // topic_id → its story section (for "read the full topic" hrefs + focus set)
  const storyByTopic = useMemo(
    () => new Map(storySections.map((s) => [s.topic_id, s])),
    [storySections]
  );

  // story-focus: recolour this story's nodes, dim the rest
  const highlight = useMemo(() => {
    if (!focusSeries) return null;
    const ids = new Set(
      storySections.filter((s) => s.series_slug === focusSeries).map((s) => s.topic_id)
    );
    if (!ids.size) return null;
    const color = stories.find((s) => s.series_slug === focusSeries)?.color ?? "#5ba4cf";
    return { topicIds: ids, color };
  }, [focusSeries, storySections, stories]);

  // give every topic belonging to a story its story's colour as a baseline
  const topicColors = useMemo(() => {
    const map = new Map<string, string>();
    for (const sec of storySections) {
      const color = stories.find((s) => s.series_slug === sec.series_slug)?.color;
      if (color) map.set(sec.topic_id, color);
    }
    return map;
  }, [storySections, stories]);

  // where "read the full topic" points: the static section blog for story
  // topics, the auto-generated topic blog otherwise
  const blogHref = useCallback(
    (t: Topic) => {
      const sec = storyByTopic.get(t.id);
      return sec ? storySectionHref(sec) : `/blogs/${t.id}`;
    },
    [storyByTopic]
  );

  const isLinked = useCallback(
    (a: string, b: string) =>
      links.some(
        (l) => (l.source === a && l.target === b) || (l.source === b && l.target === a)
      ),
    [links]
  );

  // Walk to a topic: jump back if already visited, extend the path if it's
  // connected to where we are, otherwise begin a fresh trail.
  const navigateTo = useCallback(
    (id: string) => {
      setPath((prev) => {
        const idx = prev.indexOf(id);
        if (idx !== -1) return prev.slice(0, idx + 1);
        const tail = prev[prev.length - 1];
        if (!tail || isLinked(tail, id)) return [...prev, id];
        return [id];
      });
    },
    [isLinked]
  );

  // Esc backs out of the dive-inside view (same as the close button)
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== "Escape") return;
      // leave Esc alone while typing (search box handles its own escape)
      const el = document.activeElement;
      if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) return;
      setPath((prev) => (prev.length ? [] : prev));
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  const visibleTopics = useMemo(
    () => (categoryFilter ? topics.filter((t) => t.category === categoryFilter) : topics),
    [topics, categoryFilter]
  );

  const results = useMemo(() => {
    if (!query.trim()) return [];
    const q = query.toLowerCase();
    return topics
      .filter((t) => t.name.toLowerCase().includes(q) || t.summary?.toLowerCase().includes(q))
      .slice(0, 8);
  }, [query, topics]);

  const current = path.length ? byId.get(path[path.length - 1]) ?? null : null;
  const currentConnections = useMemo(() => {
    if (!current) return [];
    const cur = current;
    return links
      .filter((l) => l.source === cur.id || l.target === cur.id)
      .flatMap((l) => {
        const topic = byId.get(l.source === cur.id ? l.target : l.source);
        return topic ? [{ topic, reason: l.reason }] : [];
      });
  }, [current, links, byId]);

  // categories are derived live from whatever the user has actually added
  const categories = useMemo(() => {
    const counts = new Map<string, number>();
    for (const t of topics) counts.set(t.category, (counts.get(t.category) ?? 0) + 1);
    return Array.from(counts.entries()).sort((a, b) => b[1] - a[1]);
  }, [topics]);

  // trail rendered newest-first (current card on top, history stacked beneath)
  const trail = useMemo(() => [...path].reverse(), [path]);

  return (
    <div className="flex h-screen flex-col overflow-hidden">
      <Nav />
      <main className="relative flex-1">
        {/* Brain fills the page */}
        <div className="absolute inset-0" data-tour="brain-canvas">
          {loaded && topics.length > 0 && (
            <BrainScene
              topics={visibleTopics}
              links={links}
              path={path}
              onSelect={(id) => id && navigateTo(id)}
              highlight={highlight}
              topicColors={topicColors}
            />
          )}
          {loaded && topics.length === 0 && (
            <div className="flex h-full items-center justify-center">
              <div className="glass max-w-sm p-10 text-center">
                <h2 className="mb-2 text-lg font-bold">Your brain is empty</h2>
                <p className="mb-4 text-sm text-muted">
                  Log your first conversation and watch topics light up here.
                </p>
                <Link href="/add" className="btn-primary">Add a learning</Link>
              </div>
            </div>
          )}
        </div>

        {/* Search overlay */}
        <div className="pointer-events-none absolute inset-x-0 top-0 z-10 p-4 sm:p-6">
          <div className="pointer-events-auto mx-auto max-w-xl">
            <div className="relative" data-tour="brain-search">
              <SearchIcon className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-faint" />
              <input
                className="input !rounded-full !pl-11"
                style={{ background: "rgba(18,15,20,0.7)", backdropFilter: "blur(20px)", boxShadow: "0 18px 50px rgba(0,0,0,0.45)" }}
                placeholder="Search your brain…"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onFocus={() => setSearchFocused(true)}
                onBlur={() => setTimeout(() => setSearchFocused(false), 150)}
              />
              {(results.length > 0 || (searchFocused && !query.trim() && categories.length > 0)) && (
                <div className="overlay-panel absolute inset-x-0 top-full mt-2 overflow-hidden !rounded-[1.5rem] p-1.5">
                  {results.map((t) => (
                    <button
                      key={t.id}
                      className="flex w-full items-center gap-3 rounded-full px-4 py-2.5 text-left transition-colors hover:bg-white/[0.06]"
                      onClick={() => {
                        navigateTo(t.id);
                        setQuery("");
                        setCategoryFilter(null);
                      }}
                    >
                      <span
                        className="h-2 w-2 shrink-0 rounded-full"
                        style={{ background: topicColors.get(t.id) ?? categoryColor(t.category) }}
                      />
                      <span className="min-w-0 flex-1 truncate text-sm font-medium">{t.name}</span>
                      <span className="text-xs text-faint">{t.mastery}%</span>
                    </button>
                  ))}
                  {/* your areas of the brain — built from the topics you've added */}
                  {searchFocused && !query.trim() && (
                    <div className="flex flex-wrap gap-1.5 p-2.5">
                      {categories.map(([c, count]) => (
                        <button
                          key={c}
                          onClick={() => setCategoryFilter(categoryFilter === c ? null : c)}
                          className="rounded-full px-3 py-1.5 text-[11px] font-medium transition-all"
                          style={{
                            background: categoryFilter === c ? `${CATEGORY_COLORS[c] ?? "#a8a29e"}2e` : "rgba(255,252,245,0.05)",
                            color: CATEGORY_COLORS[c] ?? "#a8a29e",
                          }}
                        >
                          {c} · {count}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* story focus — light up one learnable story, dim the rest */}
            {stories.length > 0 && (
              <div className="pointer-events-auto mt-3 flex flex-wrap justify-center gap-2">
                {stories.map((s) => {
                  const active = focusSeries === s.series_slug;
                  return (
                    <button
                      key={s.series_slug}
                      onClick={() => setFocusSeries(active ? null : s.series_slug)}
                      className="flex items-center gap-1.5 rounded-full px-3.5 py-1.5 text-[11px] font-semibold backdrop-blur-xl transition-all"
                      style={{
                        background: active ? `${s.color}2e` : "rgba(18,15,20,0.6)",
                        color: s.color,
                        boxShadow: "0 8px 24px rgba(0,0,0,0.35)",
                      }}
                    >
                      <span className="h-2 w-2 rounded-full" style={{ background: s.color }} />
                      {SERIES_TITLES[s.series_slug] ?? s.series_slug}
                      {active && <span className="opacity-70">✕</span>}
                    </button>
                  );
                })}
              </div>
            )}

            {/* active filter chip — the only thing that stays over the brain */}
            {categoryFilter && (
              <div className="mt-3 flex justify-center">
                <button
                  onClick={() => setCategoryFilter(null)}
                  className="flex items-center gap-1.5 rounded-full px-3.5 py-1.5 text-[11px] font-semibold backdrop-blur-xl"
                  style={{
                    background: `${CATEGORY_COLORS[categoryFilter] ?? "#a8a29e"}22`,
                    color: CATEGORY_COLORS[categoryFilter] ?? "#a8a29e",
                  }}
                >
                  {categoryFilter} <span className="opacity-70">✕</span>
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Path panel — a stack of the topics you've walked through */}
        {current && (
          <aside className="absolute bottom-24 left-4 right-4 z-10 max-h-[52%] overflow-y-auto md:bottom-auto md:left-auto md:right-6 md:top-24 md:max-h-[72%] md:w-96">
            {trail.map((id, i) => {
              const t = byId.get(id);
              if (!t) return null;
              const isCurrent = i === 0;
              // original index in the forward path (for jump-back)
              const originalIndex = path.length - 1 - i;
              const color = topicColors.get(t.id) ?? categoryColor(t.category);

              if (!isCurrent) {
                // a walked-past step — compact, click to return
                return (
                  <div key={id}>
                    <PathConnector />
                    <button
                      onClick={() => setPath(path.slice(0, originalIndex + 1))}
                      className="overlay-panel flex w-full items-center gap-3 !rounded-2xl px-4 py-3 text-left opacity-70 transition-opacity hover:opacity-100"
                    >
                      <span className="h-2 w-2 shrink-0 rounded-full" style={{ background: color }} />
                      <span className="min-w-0 flex-1 truncate text-sm font-medium">{t.name}</span>
                      <span className="micro shrink-0">step {originalIndex + 1}</span>
                    </button>
                  </div>
                );
              }

              // the current topic — expanded card
              return (
                <div key={id}>
                  {trail.length > 1 && <PathConnector />}
                  <div className="overlay-panel p-6">
                    <div className="mb-3 flex items-start justify-between gap-3">
                      <div>
                        <span
                          className="mb-1.5 inline-block rounded-full px-2.5 py-0.5 text-[11px] font-semibold"
                          style={{ background: `${color}20`, color }}
                        >
                          {t.category}
                        </span>
                        <Link
                          href={blogHref(t)}
                          target="_blank"
                          rel="noopener"
                          className="text-lg font-bold leading-snug transition-colors hover:text-[#f5b95f]"
                        >
                          {t.name}
                        </Link>
                      </div>
                      <button
                        onClick={() => setPath([])}
                        className="rounded-full p-1.5 text-faint hover:bg-white/[0.06] hover:text-white"
                        aria-label="Close"
                      >
                        ✕
                      </button>
                    </div>



                    <p className="mb-3 line-clamp-2 text-sm leading-relaxed text-white/80">{t.summary}</p>

                    <Link
                      href={blogHref(t)}
                      target="_blank"
                      rel="noopener"
                      className="group mb-5 inline-flex items-center gap-1.5 text-xs font-semibold"
                      style={{ color: color }}
                    >
                      Read the full topic
                      <span className="transition-transform group-hover:translate-x-0.5">↗</span>
                    </Link>

                    {t.key_points?.length > 0 && (
                      <>
                        <h3 className="micro mb-2">Key points</h3>
                        <ul className="mb-4 space-y-1.5">
                          {t.key_points.map((k, j) => (
                            <li key={j} className="flex gap-2 text-sm text-muted">
                              <span className="text-[#f5b95f]">•</span>
                              {k}
                            </li>
                          ))}
                        </ul>
                      </>
                    )}

                    {currentConnections.length > 0 && (
                      <>
                        <h3 className="micro mb-2">Follow a connection</h3>
                        <ul className="space-y-2">
                          {currentConnections.map((c, j) => {
                            const visited = path.includes(c.topic.id);
                            return (
                              <li key={j}>
                                <button
                                  onClick={() => navigateTo(c.topic.id)}
                                  className="row-soft flex w-full items-start gap-2.5 px-3.5 py-2.5 text-left"
                                >
                                  <span
                                    className="mt-1.5 h-1.5 w-1.5 shrink-0 rounded-full"
                                    style={{ background: topicColors.get(c.topic.id) ?? categoryColor(c.topic.category) }}
                                  />
                                  <span className="min-w-0 flex-1">
                                    <span
                                      className="text-sm font-medium"
                                      style={{ color: topicColors.get(c.topic.id) ?? categoryColor(c.topic.category) }}
                                    >
                                      {c.topic.name}
                                    </span>
                                    {visited && <span className="micro ml-2">visited</span>}
                                    {c.reason && (
                                      <span className="mt-0.5 block text-xs leading-snug text-faint">
                                        {c.reason}
                                      </span>
                                    )}
                                  </span>
                                </button>
                              </li>
                            );
                          })}
                        </ul>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </aside>
        )}

        {/* Legend / hint */}
        {!current && (
          <div className="pointer-events-none absolute bottom-24 left-1/2 z-0 -translate-x-1/2 md:bottom-6">
            <p className="micro rounded-full bg-[#100e14]/60 px-4 py-2 backdrop-blur-xl">
              hover to name · click a glow to dive inside · follow links to walk a path
            </p>
          </div>
        )}
      </main>
    </div>
  );
}

/** A small vertical link between stacked path cards. */
function PathConnector() {
  return (
    <div className="flex justify-center py-1.5" aria-hidden>
      <span className="block h-4 w-px bg-gradient-to-b from-transparent via-white/25 to-white/25" />
    </div>
  );
}

function SearchIcon({ className = "h-4 w-4" }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
      <circle cx="11" cy="11" r="7" />
      <path d="M20 20l-3.5-3.5" />
    </svg>
  );
}

@import "tailwindcss";

:root {
  /* Warm charcoal base with natural, dusk-toned accents */
  --background: #0b0a0e;
  --surface: rgba(255, 252, 245, 0.03);
  --surface-strong: rgba(255, 252, 245, 0.055);
  --border: rgba(255, 252, 245, 0.07);
  --border-strong: rgba(255, 252, 245, 0.15);
  --foreground: #f2f0eb;
  --muted: #a5a1ab;
  --faint: #6d6875;
  --ember: #ff7a5c;      /* primary — warm coral */
  --gold: #f5b95f;       /* progress, reward */
  --teal: #43d6b5;       /* growth, success */
  --sage: #8fd694;
  --success: #62d99b;
  --warning: #f5b95f;
  --danger: #f87171;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-muted: var(--muted);
  --color-faint: var(--faint);
  --color-ember: var(--ember);
  --color-gold: var(--gold);
  --color-teal: var(--teal);
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-danger: var(--danger);
  --font-sans: var(--font-inter);
  --font-display: var(--font-grotesk);
  --font-mono: var(--font-jetmono);
  --font-serif: var(--font-serif);
}

html {
  color-scheme: dark;
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-inter), system-ui, sans-serif;
  font-size: 16px;
  line-height: 1.65;
  letter-spacing: 0.01em;
  -webkit-font-smoothing: antialiased;
}

/* ---------- Ambient fluidic mesh background ---------- */
.ambient {
  position: fixed;
  inset: 0;
  z-index: -2;
  pointer-events: none;
  background:
    radial-gradient(circle at 8% 5%, rgba(255, 122, 92, 0.07) 0%, transparent 45%),
    radial-gradient(circle at 92% 12%, rgba(67, 214, 181, 0.055) 0%, transparent 45%),
    radial-gradient(circle at 15% 90%, rgba(245, 185, 95, 0.05) 0%, transparent 50%),
    radial-gradient(circle at 85% 85%, rgba(159, 140, 255, 0.04) 0%, transparent 45%),
    var(--background);
}
.ambient::after {
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(to right, rgba(255, 252, 245, 0.5) 1px, transparent 1px),
    linear-gradient(to bottom, rgba(255, 252, 245, 0.5) 1px, transparent 1px);
  background-size: 56px 56px;
  opacity: 0.016;
  mask-image: radial-gradient(ellipse 75% 55% at 50% 0%, black, transparent 80%);
}

/* Slow-morphing colour blobs floating behind content */
@keyframes blob {
  0%   { transform: translate(0, 0) scale(1); }
  33%  { transform: translate(40px, -50px) scale(1.1); }
  66%  { transform: translate(-30px, 30px) scale(0.92); }
  100% { transform: translate(0, 0) scale(1); }
}
.blob {
  position: fixed;
  z-index: -1;
  border-radius: 9999px;
  pointer-events: none;
  filter: blur(110px);
  opacity: 0.13;
  animation: blob 18s ease-in-out infinite;
  will-change: transform;
}
.blob-ember { background: #ff7a5c; width: 420px; height: 420px; top: -8%; left: -6%; }
.blob-teal  { background: #43d6b5; width: 380px; height: 380px; top: 30%; right: -8%; animation-delay: -6s; animation-duration: 22s; }
.blob-gold  { background: #f5b95f; width: 340px; height: 340px; bottom: -10%; left: 22%; animation-delay: -12s; animation-duration: 26s; opacity: 0.09; }

/* ---------- Typography ---------- */
h1, h2, h3, .display {
  font-family: var(--font-grotesk), var(--font-inter), sans-serif;
  letter-spacing: -0.025em;
  font-weight: 700;
}

/* Warm gradient headline text */
.text-warm-gradient {
  background: linear-gradient(100deg, #f2f0eb 20%, #e8d5c4 55%, #b9b2bf 90%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

/* Instrument-panel micro label */
.micro {
  font-family: var(--font-jetmono), monospace;
  font-size: 10px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--faint);
  font-weight: 600;
}

/* ---------- Long-form reading (topic blog pages) ---------- */
.article-lead {
  font-family: var(--font-serif), Georgia, serif;
  font-optical-sizing: auto;
  font-size: 1.375rem;
  line-height: 1.65;
  letter-spacing: -0.01em;
  color: rgba(242, 240, 235, 0.92);
}
.article-body {
  font-family: var(--font-serif), Georgia, serif;
  font-optical-sizing: auto;
  font-size: 1.15rem;
  line-height: 1.85;
  letter-spacing: -0.003em;
  color: rgba(242, 240, 235, 0.82);
}
/* graceful first-letter flourish on the opening paragraph */
.article-lead::first-letter {
  initial-letter: 3;
  font-family: var(--font-grotesk), sans-serif;
  font-weight: 700;
  color: var(--gold);
  margin-right: 0.6rem;
}

/* ---------- Surfaces ---------- */
/* Borderless surface — a soft wash of light that dissolves into the page */
.glass {
  position: relative;
  background: linear-gradient(
    165deg,
    rgba(255, 252, 245, 0.045) 0%,
    rgba(255, 252, 245, 0.014) 55%,
    rgba(255, 252, 245, 0) 100%
  );
  border: none;
  border-radius: 2rem;
}
.glass::before {
  content: "";
  position: absolute;
  top: 0;
  left: 12%;
  right: 12%;
  height: 1px;
  border-radius: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 252, 245, 0.14), transparent);
  pointer-events: none;
}
.glass-hover {
  transition: background 0.25s ease, transform 0.25s ease;
}
.glass-hover:hover {
  background: linear-gradient(
    165deg,
    rgba(255, 252, 245, 0.07) 0%,
    rgba(255, 252, 245, 0.02) 55%,
    rgba(255, 252, 245, 0) 100%
  );
  transform: translateY(-3px);
}

/* Solid readable panel for overlays floating above the 3D brain canvas */
.overlay-panel {
  position: relative;
  background: linear-gradient(170deg, rgba(20, 17, 22, 0.92), rgba(13, 11, 15, 0.86));
  backdrop-filter: blur(20px);
  border: none;
  border-radius: 1.75rem;
  box-shadow: 0 30px 80px -30px rgba(0, 0, 0, 0.8);
}
.overlay-panel::before {
  content: "";
  position: absolute;
  top: 0;
  left: 12%;
  right: 12%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 252, 245, 0.16), transparent);
  pointer-events: none;
}

/* Guided-tour step card — translucent panel floating beside the spotlight */
.tour-card {
  position: fixed;
  z-index: 130;
  pointer-events: auto;
  padding: 1.4rem 1.5rem 1.25rem;
  background: linear-gradient(170deg, rgba(24, 20, 28, 0.86), rgba(12, 10, 16, 0.8));
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border-radius: 1.75rem;
  box-shadow: 0 30px 90px -20px rgba(0, 0, 0, 0.85);
  max-height: calc(100vh - 32px);
  overflow: auto;
  animation: tour-in 0.45s cubic-bezier(0.22, 1, 0.36, 1);
}
.tour-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 12%;
  right: 12%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 252, 245, 0.18), transparent);
  pointer-events: none;
}
@keyframes tour-in {
  from { opacity: 0; transform: translateY(12px) scale(0.98); }
  to   { opacity: 1; transform: translateY(0) scale(1); }
}

/* Inner soft row — invisible until touched */
.row-soft {
  background: transparent;
  border: none;
  border-radius: 1.25rem;
  transition: background 0.2s ease;
}
.row-soft:hover {
  background: rgba(255, 252, 245, 0.04);
}

/* ---------- Buttons ---------- */
.btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  border-radius: 9999px;
  padding: 0.75rem 1.75rem;
  font-weight: 600;
  font-size: 0.8rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #131118;
  background: #f4f1e9;
  box-shadow: 0 10px 34px rgba(244, 241, 233, 0.12);
  transition: box-shadow 0.25s ease, transform 0.2s ease, opacity 0.2s ease, background 0.2s ease;
}
.btn-primary:hover:not(:disabled) {
  background: #ffffff;
  box-shadow: 0 14px 44px rgba(244, 241, 233, 0.2);
  transform: translateY(-2px);
}
.btn-primary:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  border-radius: 9999px;
  padding: 0.75rem 1.5rem;
  font-weight: 500;
  font-size: 0.85rem;
  color: var(--foreground);
  background: rgba(255, 252, 245, 0.05);
  border: none;
  transition: background 0.2s ease, transform 0.2s ease;
}
.btn-ghost:hover:not(:disabled) {
  background: rgba(255, 252, 245, 0.09);
  transform: translateY(-2px);
}
.btn-ghost:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

/* ---------- Inputs ---------- */
.input {
  width: 100%;
  border-radius: 1.25rem;
  padding: 0.8rem 1.15rem;
  background: rgba(255, 252, 245, 0.04);
  border: 1px solid transparent;
  color: var(--foreground);
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
}
.input::placeholder {
  color: var(--faint);
}
.input:focus {
  background: rgba(255, 252, 245, 0.06);
  border-color: rgba(255, 122, 92, 0.35);
  box-shadow: 0 0 0 4px rgba(255, 122, 92, 0.08);
}

/* ---------- Motion ---------- */
@keyframes rise {
  from { opacity: 0; transform: translateY(14px); }
  to { opacity: 1; transform: translateY(0); }
}
.rise {
  animation: rise 0.55s cubic-bezier(0.22, 1, 0.36, 1) both;
}
.rise-1 { animation-delay: 0.06s; }
.rise-2 { animation-delay: 0.14s; }
.rise-3 { animation-delay: 0.22s; }
.rise-4 { animation-delay: 0.3s; }

@keyframes pulseGlow {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}
.pulse-glow {
  animation: pulseGlow 2.4s ease-in-out infinite;
}

/* Live status dot (ping) */
@keyframes ping {
  75%, 100% { transform: scale(2.4); opacity: 0; }
}
.ping-dot {
  position: relative;
  display: inline-flex;
  height: 7px;
  width: 7px;
}
.ping-dot::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 9999px;
  background: currentColor;
  animation: ping 2s cubic-bezier(0, 0, 0.2, 1) infinite;
  opacity: 0.6;
}
.ping-dot::after {
  content: "";
  position: relative;
  border-radius: 9999px;
  background: currentColor;
  width: 100%;
  height: 100%;
}

/* ---------- Chrome ---------- */
::-webkit-scrollbar { width: 10px; height: 10px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: rgba(255, 252, 245, 0.1);
  border-radius: 8px;
  border: 2px solid var(--background);
}
::-webkit-scrollbar-thumb:hover { background: rgba(255, 252, 245, 0.18); }

::selection {
  background: rgba(255, 122, 92, 0.45);
  color: #fff;
}

/* ==========================================================================
   PAPER MODE (E-Ink Parchment Theme — reading views only)
   ========================================================================== */

.paper-mode-active {
  /* ---- page + ink ---- */
  --background: #eee8dd;   /* page (unchanged; keep == animation PAPER_BG) */
  --foreground: #2f2a24;   /* body ink            ~10:1  */
  --ink:        #231f1a;   /* strongest ink: headings + bold emphasis  ~13:1 */
  --muted:      #544d42;   /* secondary text      ~6:1   */
  --faint:      #655d4f;   /* micro labels        ~4.6:1 (was #8a8174 ~2.3:1) */

  /* ---- elevation ramp (cards LIGHTER than page + real border/shadow) ---- */
  --surface:    #f6f1e6;   /* cards / glass — a fresh sheet, lighter than the page */
  --surface-2:  #efe9dc;   /* hover / nested */
  --border:     #dcd2be;   /* warm hairline that actually shows */
  --code-bg:    #f3ecdd;   /* code panel (warm parchment) */
  --code-border:#ddd3bf;

  /* ---- accents retuned for a LIGHT background (darker, saturated ink) ---- */
  --ember:  #c0361d;   /* vermilion   ~5.2:1  (dark-mode #ff7a5c/#ff9a80 map here) */
  --gold:   #9a6410;   /* ochre       ~4.8:1  (#f5b95f maps here) */
  --teal:   #0f6b60;   /* pen teal    ~5.4:1  (#43d6b5/#7fe5cb map here) */
  --violet: #5b3fb5;   /* (#a78bfa)   ~6:1  */
  --blue:   #245f8f;   /* (#5ba4cf)   ~5.8:1 */
  --cyan:   #0e7490;   /* (#22d3ee)   ~5.2:1 */
  --lime:   #5a7d10;   /* (#a3e635)   ~4.3:1 */

  color-scheme: light;
  background-color: var(--background) !important;
  color: var(--foreground) !important;
  min-height: 100vh;
  position: relative;
}

/* Authentic physical e-ink paper grain texture overlay (softened) */
.paper-mode-active::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.75' numOctaves='3' stitchTiles='stitch'/%3E%3CfeColorMatrix type='saturate' values='0'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.045'/%3E%3C/svg%3E");
  opacity: 0.5 !important;
}

/* Hide dark mode ambient mesh & glowing floating blobs */
.paper-mode-active .ambient,
.paper-mode-active .blob {
  opacity: 0 !important;
  pointer-events: none !important;
}

/* Warm ink headlines */
.paper-mode-active .text-warm-gradient {
  background: linear-gradient(120deg, var(--ink) 20%, #3a342d 70%, var(--muted) 100%) !important;
  -webkit-background-clip: text !important;
  background-clip: text !important;
  color: transparent !important;
}

.paper-mode-active h1,
.paper-mode-active h2,
.paper-mode-active h3,
.paper-mode-active .display {
  color: var(--ink) !important;
}

.paper-mode-active p,
.paper-mode-active span,
.paper-mode-active li {
  color: inherit;
}

/* Long-form reading typography in Paper Mode */
.paper-mode-active .article-lead {
  color: #2e2823 !important;
}
.paper-mode-active .article-body {
  color: var(--foreground) !important;
}
.paper-mode-active .article-lead::first-letter {
  color: var(--gold) !important;
}

/* Surfaces & Cards in Paper Mode */
.paper-mode-active .glass {
  background: var(--surface) !important;
  border: 1px solid var(--border) !important;
  box-shadow: 0 1px 2px rgba(60, 50, 40, 0.05),
              0 10px 30px -14px rgba(60, 50, 40, 0.18) !important;
}
.paper-mode-active .glass::before {
  background: linear-gradient(90deg, transparent, rgba(45, 41, 38, 0.10), transparent) !important;
}
.paper-mode-active .glass-hover:hover {
  background: var(--surface-2) !important;
  box-shadow: 0 2px 4px rgba(60, 50, 40, 0.06),
              0 14px 36px -14px rgba(60, 50, 40, 0.22) !important;
}

.paper-mode-active details {
  background: var(--surface) !important;
  border-color: var(--border) !important;
}
.paper-mode-active details[open] {
  background: var(--surface-2) !important;
}
.paper-mode-active .row-soft:hover {
  background: rgba(45, 41, 38, 0.05) !important;
}
.paper-mode-active hr {
  border-color: var(--border) !important;
}

/* Remap leaked dark-mode white utility classes */
.paper-mode-active [class*="text-white"]:not([class*="text-white/"]) {
  color: var(--ink) !important;
}
.paper-mode-active [class*="text-white/9"],
.paper-mode-active [class*="text-white/8"] {
  color: var(--foreground) !important;
}
.paper-mode-active [class*="text-white/7"],
.paper-mode-active [class*="text-white/6"],
.paper-mode-active [class*="text-white/5"],
.paper-mode-active [class*="text-white/4"] {
  color: var(--muted) !important;
}

.paper-mode-active [class*="bg-white/"] {
  background-color: rgba(58, 50, 38, 0.05) !important;
}
.paper-mode-active [class*="border-white/"] {
  border-color: rgba(58, 50, 38, 0.14) !important;
}

/* Remap dark-mode neon accent text — class form */
.paper-mode-active [class*="text-[#43d6b5]"],
.paper-mode-active [class*="text-[#7fe5cb]"] { color: var(--teal) !important; }
.paper-mode-active [class*="text-[#f5b95f]"],
.paper-mode-active [class*="text-[#f5d9a8]"] { color: var(--gold) !important; }
.paper-mode-active [class*="text-[#ff7a5c]"],
.paper-mode-active [class*="text-[#ff9a80]"],
.paper-mode-active [class*="text-[#ffe3d7]"],
.paper-mode-active [class*="text-[#ffb09b]"] { color: var(--ember) !important; }
.paper-mode-active [class*="text-[#a78bfa]"],
.paper-mode-active [class*="text-[#bfa8f5]"] { color: var(--violet) !important; }
.paper-mode-active [class*="text-[#5ba4cf]"] { color: var(--blue) !important; }
.paper-mode-active [class*="text-[#22d3ee]"],
.paper-mode-active [class*="text-[#7fd0e8]"] { color: var(--cyan) !important; }
.paper-mode-active [class*="text-[#a3e635]"] { color: var(--lime) !important; }
.paper-mode-active [class*="text-[#f87171]"] { color: var(--ember) !important; }

/* Remap dark-mode neon accent text — inline-style form (difficulty pills, eyebrows, viz) */
.paper-mode-active [style*="color:#43d6b5"],
.paper-mode-active [style*="color:#7fe5cb"] { color: var(--teal) !important; }
.paper-mode-active [style*="color:#f5b95f"],
.paper-mode-active [style*="color:#f5d9a8"] { color: var(--gold) !important; }
.paper-mode-active [style*="color:#ff7a5c"],
.paper-mode-active [style*="color:#ff9a80"],
.paper-mode-active [style*="color:#ffe3d7"],
.paper-mode-active [style*="color:#ffb09b"] { color: var(--ember) !important; }
.paper-mode-active [style*="color:#a78bfa"],
.paper-mode-active [style*="color:#bfa8f5"] { color: var(--violet) !important; }
.paper-mode-active [style*="color:#5ba4cf"] { color: var(--blue) !important; }
.paper-mode-active [style*="color:#22d3ee"],
.paper-mode-active [style*="color:#7fd0e8"] { color: var(--cyan) !important; }
.paper-mode-active [style*="color:#a3e635"] { color: var(--lime) !important; }
.paper-mode-active [style*="color:#f87171"] { color: var(--ember) !important; }

/* Remap dark-mode accent fills — class & style form (difficulty pills, chips) */
.paper-mode-active [class*="bg-[#43d6b5]"],
.paper-mode-active [style*="background:#43d6b5"] { background-color: rgba(15, 107, 96, 0.12) !important; }
.paper-mode-active [class*="bg-[#f5b95f]"],
.paper-mode-active [style*="background:#f5b95f"] { background-color: rgba(154, 100, 16, 0.12) !important; }
.paper-mode-active [class*="bg-[#ff7a5c]"],
.paper-mode-active [style*="background:#ff7a5c"] { background-color: rgba(192, 54, 29, 0.12) !important; }
.paper-mode-active [class*="bg-[#bfa8f5]"],
.paper-mode-active [style*="background:#bfa8f5"] { background-color: rgba(91, 63, 181, 0.12) !important; }

/* Code blocks & Markdown in Paper Mode */
.paper-mode-active pre {
  background: var(--code-bg) !important;
  border: 1px solid var(--code-border) !important;
  color: #2b2620 !important;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.55),
              0 1px 2px rgba(60, 50, 40, 0.05) !important;
}
.paper-mode-active pre code {
  color: #2b2620 !important;
}
.paper-mode-active code {
  background: var(--code-bg) !important;
  color: var(--gold) !important;
  border: 1px solid var(--code-border) !important;
}
.paper-mode-active blockquote {
  border-left-color: var(--gold) !important;
  color: #4a423a !important;
}
.paper-mode-active table {
  border-color: var(--border) !important;
}
.paper-mode-active th,
.paper-mode-active td {
  border-color: var(--border) !important;
}

/* Top Bar & Navigation in Paper Mode */
.paper-mode-active header {
  background: linear-gradient(to bottom, rgba(238, 232, 221, 0.96), rgba(238, 232, 221, 0.75), transparent) !important;
}
.paper-mode-active header .display {
  color: var(--ink) !important;
}
.paper-mode-active nav {
  background: rgba(45, 41, 38, 0.06) !important;
}
.paper-mode-active nav a {
  color: var(--muted) !important;
}
.paper-mode-active nav a:hover {
  background: rgba(45, 41, 38, 0.09) !important;
  color: var(--ink) !important;
}
.paper-mode-active nav a.bg-\[\#f4f1e9\] {
  background: var(--ink) !important;
  color: var(--background) !important;
  box-shadow: 0 4px 16px rgba(28, 26, 23, 0.2) !important;
}

/* Buttons & Inputs in Paper Mode */
.paper-mode-active .btn-primary {
  background: var(--ink) !important;
  color: var(--background) !important;
  box-shadow: 0 6px 20px rgba(28, 26, 23, 0.18) !important;
}
.paper-mode-active .btn-primary:hover:not(:disabled) {
  background: #39332d !important;
  box-shadow: 0 10px 28px rgba(28, 26, 23, 0.28) !important;
}
.paper-mode-active .btn-ghost {
  background: rgba(45, 41, 38, 0.06) !important;
  color: var(--ink) !important;
}
.paper-mode-active .btn-ghost:hover:not(:disabled) {
  background: rgba(45, 41, 38, 0.12) !important;
}
.paper-mode-active .input {
  background: var(--code-bg) !important;
  border-color: var(--border) !important;
  color: var(--ink) !important;
}
.paper-mode-active .input::placeholder {
  color: var(--faint) !important;
}
.paper-mode-active .input:focus {
  background: var(--surface) !important;
  border-color: var(--gold) !important;
  box-shadow: 0 0 0 4px rgba(154, 100, 16, 0.15) !important;
}

.paper-mode-active ::selection {
  background: rgba(154, 100, 16, 0.25);
  color: var(--ink);
}

@media (prefers-reduced-motion: reduce) {
  body {
    transition: background-color 300ms ease, color 300ms ease;
  }
}

@import "tailwindcss";

:root {
  /* Warm charcoal base with natural, dusk-toned accents */
  --background: #0b0a0e;
  --surface: rgba(255, 252, 245, 0.03);
  --surface-strong: rgba(255, 252, 245, 0.055);
  --border: rgba(255, 252, 245, 0.07);
  --border-strong: rgba(255, 252, 245, 0.15);
  --foreground: #f2f0eb;
  --muted: #a5a1ab;
  --faint: #6d6875;
  --ember: #ff7a5c;      /* primary — warm coral */
  --gold: #f5b95f;       /* progress, reward */
  --teal: #43d6b5;       /* growth, success */
  --sage: #8fd694;
  --success: #62d99b;
  --warning: #f5b95f;
  --danger: #f87171;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-muted: var(--muted);
  --color-faint: var(--faint);
  --color-ember: var(--ember);
  --color-gold: var(--gold);
  --color-teal: var(--teal);
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-danger: var(--danger);
  --font-sans: var(--font-inter);
  --font-display: var(--font-grotesk);
  --font-mono: var(--font-jetmono);
  --font-serif: var(--font-serif);
}

html {
  color-scheme: dark;
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-inter), system-ui, sans-serif;
  font-size: 16px;
  line-height: 1.65;
  letter-spacing: 0.01em;
  -webkit-font-smoothing: antialiased;
}

/* ---------- Ambient fluidic mesh background ---------- */
.ambient {
  position: fixed;
  inset: 0;
  z-index: -2;
  pointer-events: none;
  background:
    radial-gradient(circle at 8% 5%, rgba(255, 122, 92, 0.07) 0%, transparent 45%),
    radial-gradient(circle at 92% 12%, rgba(67, 214, 181, 0.055) 0%, transparent 45%),
    radial-gradient(circle at 15% 90%, rgba(245, 185, 95, 0.05) 0%, transparent 50%),
    radial-gradient(circle at 85% 85%, rgba(159, 140, 255, 0.04) 0%, transparent 45%),
    var(--background);
}
.ambient::after {
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(to right, rgba(255, 252, 245, 0.5) 1px, transparent 1px),
    linear-gradient(to bottom, rgba(255, 252, 245, 0.5) 1px, transparent 1px);
  background-size: 56px 56px;
  opacity: 0.016;
  mask-image: radial-gradient(ellipse 75% 55% at 50% 0%, black, transparent 80%);
}

/* Slow-morphing colour blobs floating behind content */
@keyframes blob {
  0%   { transform: translate(0, 0) scale(1); }
  33%  { transform: translate(40px, -50px) scale(1.1); }
  66%  { transform: translate(-30px, 30px) scale(0.92); }
  100% { transform: translate(0, 0) scale(1); }
}
.blob {
  position: fixed;
  z-index: -1;
  border-radius: 9999px;
  pointer-events: none;
  filter: blur(110px);
  opacity: 0.13;
  animation: blob 18s ease-in-out infinite;
  will-change: transform;
}
.blob-ember { background: #ff7a5c; width: 420px; height: 420px; top: -8%; left: -6%; }
.blob-teal  { background: #43d6b5; width: 380px; height: 380px; top: 30%; right: -8%; animation-delay: -6s; animation-duration: 22s; }
.blob-gold  { background: #f5b95f; width: 340px; height: 340px; bottom: -10%; left: 22%; animation-delay: -12s; animation-duration: 26s; opacity: 0.09; }

/* ---------- Typography ---------- */
h1, h2, h3, .display {
  font-family: var(--font-grotesk), var(--font-inter), sans-serif;
  letter-spacing: -0.025em;
  font-weight: 700;
}

/* Warm gradient headline text */
.text-warm-gradient {
  background: linear-gradient(100deg, #f2f0eb 20%, #e8d5c4 55%, #b9b2bf 90%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

/* Instrument-panel micro label */
.micro {
  font-family: var(--font-jetmono), monospace;
  font-size: 10px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--faint);
  font-weight: 600;
}

/* ---------- Long-form reading (topic blog pages) ---------- */
.article-lead {
  font-family: var(--font-serif), Georgia, serif;
  font-optical-sizing: auto;
  font-size: 1.375rem;
  line-height: 1.65;
  letter-spacing: -0.01em;
  color: rgba(242, 240, 235, 0.92);
}
.article-body {
  font-family: var(--font-serif), Georgia, serif;
  font-optical-sizing: auto;
  font-size: 1.15rem;
  line-height: 1.85;
  letter-spacing: -0.003em;
  color: rgba(242, 240, 235, 0.82);
}
/* graceful first-letter flourish on the opening paragraph */
.article-lead::first-letter {
  initial-letter: 3;
  font-family: var(--font-grotesk), sans-serif;
  font-weight: 700;
  color: var(--gold);
  margin-right: 0.6rem;
}

/* ---------- Surfaces ---------- */
/* Borderless surface — a soft wash of light that dissolves into the page */
.glass {
  position: relative;
  background: linear-gradient(
    165deg,
    rgba(255, 252, 245, 0.045) 0%,
    rgba(255, 252, 245, 0.014) 55%,
    rgba(255, 252, 245, 0) 100%
  );
  border: none;
  border-radius: 2rem;
}
.glass::before {
  content: "";
  position: absolute;
  top: 0;
  left: 12%;
  right: 12%;
  height: 1px;
  border-radius: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 252, 245, 0.14), transparent);
  pointer-events: none;
}
.glass-hover {
  transition: background 0.25s ease, transform 0.25s ease;
}
.glass-hover:hover {
  background: linear-gradient(
    165deg,
    rgba(255, 252, 245, 0.07) 0%,
    rgba(255, 252, 245, 0.02) 55%,
    rgba(255, 252, 245, 0) 100%
  );
  transform: translateY(-3px);
}

/* Solid readable panel for overlays floating above the 3D brain canvas */
.overlay-panel {
  position: relative;
  background: linear-gradient(170deg, rgba(20, 17, 22, 0.92), rgba(13, 11, 15, 0.86));
  backdrop-filter: blur(20px);
  border: none;
  border-radius: 1.75rem;
  box-shadow: 0 30px 80px -30px rgba(0, 0, 0, 0.8);
}
.overlay-panel::before {
  content: "";
  position: absolute;
  top: 0;
  left: 12%;
  right: 12%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 252, 245, 0.16), transparent);
  pointer-events: none;
}

/* Guided-tour step card — translucent panel floating beside the spotlight */
.tour-card {
  position: fixed;
  z-index: 130;
  pointer-events: auto;
  padding: 1.4rem 1.5rem 1.25rem;
  background: linear-gradient(170deg, rgba(24, 20, 28, 0.86), rgba(12, 10, 16, 0.8));
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border-radius: 1.75rem;
  box-shadow: 0 30px 90px -20px rgba(0, 0, 0, 0.85);
  max-height: calc(100vh - 32px);
  overflow: auto;
  animation: tour-in 0.45s cubic-bezier(0.22, 1, 0.36, 1);
}
.tour-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 12%;
  right: 12%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 252, 245, 0.18), transparent);
  pointer-events: none;
}
@keyframes tour-in {
  from { opacity: 0; transform: translateY(12px) scale(0.98); }
  to   { opacity: 1; transform: translateY(0) scale(1); }
}

/* Inner soft row — invisible until touched */
.row-soft {
  background: transparent;
  border: none;
  border-radius: 1.25rem;
  transition: background 0.2s ease;
}
.row-soft:hover {
  background: rgba(255, 252, 245, 0.04);
}

/* ---------- Buttons ---------- */
.btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  border-radius: 9999px;
  padding: 0.75rem 1.75rem;
  font-weight: 600;
  font-size: 0.8rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #131118;
  background: #f4f1e9;
  box-shadow: 0 10px 34px rgba(244, 241, 233, 0.12);
  transition: box-shadow 0.25s ease, transform 0.2s ease, opacity 0.2s ease, background 0.2s ease;
}
.btn-primary:hover:not(:disabled) {
  background: #ffffff;
  box-shadow: 0 14px 44px rgba(244, 241, 233, 0.2);
  transform: translateY(-2px);
}
.btn-primary:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  border-radius: 9999px;
  padding: 0.75rem 1.5rem;
  font-weight: 500;
  font-size: 0.85rem;
  color: var(--foreground);
  background: rgba(255, 252, 245, 0.05);
  border: none;
  transition: background 0.2s ease, transform 0.2s ease;
}
.btn-ghost:hover:not(:disabled) {
  background: rgba(255, 252, 245, 0.09);
  transform: translateY(-2px);
}
.btn-ghost:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

/* ---------- Inputs ---------- */
.input {
  width: 100%;
  border-radius: 1.25rem;
  padding: 0.8rem 1.15rem;
  background: rgba(255, 252, 245, 0.04);
  border: 1px solid transparent;
  color: var(--foreground);
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
}
.input::placeholder {
  color: var(--faint);
}
.input:focus {
  background: rgba(255, 252, 245, 0.06);
  border-color: rgba(255, 122, 92, 0.35);
  box-shadow: 0 0 0 4px rgba(255, 122, 92, 0.08);
}

/* ---------- Motion ---------- */
@keyframes rise {
  from { opacity: 0; transform: translateY(14px); }
  to { opacity: 1; transform: translateY(0); }
}
.rise {
  animation: rise 0.55s cubic-bezier(0.22, 1, 0.36, 1) both;
}
.rise-1 { animation-delay: 0.06s; }
.rise-2 { animation-delay: 0.14s; }
.rise-3 { animation-delay: 0.22s; }
.rise-4 { animation-delay: 0.3s; }

@keyframes pulseGlow {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}
.pulse-glow {
  animation: pulseGlow 2.4s ease-in-out infinite;
}

/* Live status dot (ping) */
@keyframes ping {
  75%, 100% { transform: scale(2.4); opacity: 0; }
}
.ping-dot {
  position: relative;
  display: inline-flex;
  height: 7px;
  width: 7px;
}
.ping-dot::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 9999px;
  background: currentColor;
  animation: ping 2s cubic-bezier(0, 0, 0.2, 1) infinite;
  opacity: 0.6;
}
.ping-dot::after {
  content: "";
  position: relative;
  border-radius: 9999px;
  background: currentColor;
  width: 100%;
  height: 100%;
}

/* ---------- Chrome ---------- */
::-webkit-scrollbar { width: 10px; height: 10px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: rgba(255, 252, 245, 0.1);
  border-radius: 8px;
  border: 2px solid var(--background);
}
::-webkit-scrollbar-thumb:hover { background: rgba(255, 252, 245, 0.18); }

::selection {
  background: rgba(255, 122, 92, 0.45);
  color: #fff;
}

/* ==========================================================================
   PAPER MODE (E-Ink Parchment Theme — reading views only)
   ========================================================================== */

.paper-mode-active {
  /* ---- page + ink ---- */
  --background: #eee8dd;   /* page (unchanged; keep == animation PAPER_BG) */
  --foreground: #2f2a24;   /* body ink            ~10:1  */
  --ink:        #231f1a;   /* strongest ink: headings + bold emphasis  ~13:1 */
  --muted:      #544d42;   /* secondary text      ~6:1   */
  --faint:      #655d4f;   /* micro labels        ~4.6:1 (was #8a8174 ~2.3:1) */

  /* ---- elevation ramp (cards LIGHTER than page + real border/shadow) ---- */
  --surface:    #f6f1e6;   /* cards / glass — a fresh sheet, lighter than the page */
  --surface-2:  #efe9dc;   /* hover / nested */
  --border:     #dcd2be;   /* warm hairline that actually shows */
  --code-bg:    #f3ecdd;   /* code panel (warm parchment) */
  --code-border:#ddd3bf;

  /* ---- accents retuned for a LIGHT background (darker, saturated ink) ---- */
  --ember:  #c0361d;   /* vermilion   ~5.2:1  (dark-mode #ff7a5c/#ff9a80 map here) */
  --gold:   #9a6410;   /* ochre       ~4.8:1  (#f5b95f maps here) */
  --teal:   #0f6b60;   /* pen teal    ~5.4:1  (#43d6b5/#7fe5cb map here) */
  --violet: #5b3fb5;   /* (#a78bfa)   ~6:1  */
  --blue:   #245f8f;   /* (#5ba4cf)   ~5.8:1 */
  --cyan:   #0e7490;   /* (#22d3ee)   ~5.2:1 */
  --lime:   #5a7d10;   /* (#a3e635)   ~4.3:1 */

  color-scheme: light;
  background-color: var(--background) !important;
  color: var(--foreground) !important;
  min-height: 100vh;
  position: relative;
}

/* Authentic physical e-ink paper grain texture overlay (softened) */
.paper-mode-active::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.75' numOctaves='3' stitchTiles='stitch'/%3E%3CfeColorMatrix type='saturate' values='0'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.045'/%3E%3C/svg%3E");
  opacity: 0.5 !important;
}

/* Hide dark mode ambient mesh & glowing floating blobs */
.paper-mode-active .ambient,
.paper-mode-active .blob {
  opacity: 0 !important;
  pointer-events: none !important;
}

/* Warm ink headlines */
.paper-mode-active .text-warm-gradient {
  background: linear-gradient(120deg, var(--ink) 20%, #3a342d 70%, var(--muted) 100%) !important;
  -webkit-background-clip: text !important;
  background-clip: text !important;
  color: transparent !important;
}

.paper-mode-active h1,
.paper-mode-active h2,
.paper-mode-active h3,
.paper-mode-active .display {
  color: var(--ink) !important;
}

.paper-mode-active p,
.paper-mode-active span,
.paper-mode-active li {
  color: inherit;
}

/* Long-form reading typography in Paper Mode */
.paper-mode-active .article-lead {
  color: #2e2823 !important;
}
.paper-mode-active .article-body {
  color: var(--foreground) !important;
}
.paper-mode-active .article-lead::first-letter {
  color: var(--gold) !important;
}

/* Surfaces & Cards in Paper Mode */
.paper-mode-active .glass {
  background: var(--surface) !important;
  border: 1px solid var(--border) !important;
  box-shadow: 0 1px 2px rgba(60, 50, 40, 0.05),
              0 10px 30px -14px rgba(60, 50, 40, 0.18) !important;
}
.paper-mode-active .glass::before {
  background: linear-gradient(90deg, transparent, rgba(45, 41, 38, 0.10), transparent) !important;
}
.paper-mode-active .glass-hover:hover {
  background: var(--surface-2) !important;
  box-shadow: 0 2px 4px rgba(60, 50, 40, 0.06),
              0 14px 36px -14px rgba(60, 50, 40, 0.22) !important;
}

.paper-mode-active details {
  background: var(--surface) !important;
  border-color: var(--border) !important;
}
.paper-mode-active details[open] {
  background: var(--surface-2) !important;
}
.paper-mode-active .row-soft:hover {
  background: rgba(45, 41, 38, 0.05) !important;
}
.paper-mode-active hr {
  border-color: var(--border) !important;
}

/* Remap leaked dark-mode white utility classes */
.paper-mode-active [class*="text-white"]:not([class*="text-white/"]) {
  color: var(--ink) !important;
}
.paper-mode-active [class*="text-white/9"],
.paper-mode-active [class*="text-white/8"] {
  color: var(--foreground) !important;
}
.paper-mode-active [class*="text-white/7"],
.paper-mode-active [class*="text-white/6"],
.paper-mode-active [class*="text-white/5"],
.paper-mode-active [class*="text-white/4"] {
  color: var(--muted) !important;
}

.paper-mode-active [class*="bg-white/"] {
  background-color: rgba(58, 50, 38, 0.05) !important;
}
.paper-mode-active [class*="border-white/"] {
  border-color: rgba(58, 50, 38, 0.14) !important;
}

/* Inline near-white text colours (blog-series hub titles etc. use
   style={{ color: "rgba(255,252,245,.92)" }} which the class remaps miss) */
.paper-mode-active [style*="color:rgba(255,252,245"],
.paper-mode-active [style*="color: rgba(255,252,245"],
.paper-mode-active [style*="color:rgba(255, 252, 245"] {
  color: var(--ink) !important;
}

/* viz:* reading diagrams — SVG uses near-white presentation `fill`/`stroke`
   attributes that vanish on cream. CSS fill/stroke override those attributes. */
.paper-mode-active svg text[fill^="rgba(255,252,245"] {
  fill: var(--ink) !important;
}
.paper-mode-active svg [fill="rgba(255,252,245,0.04)"],
.paper-mode-active svg [fill="rgba(255,252,245,0.05)"],
.paper-mode-active svg [fill="rgba(255,252,245,0.06)"],
.paper-mode-active svg [fill="rgba(255,252,245,0.08)"] {
  fill: rgba(58, 50, 38, 0.05) !important;
}
.paper-mode-active svg [stroke^="rgba(255,252,245"] {
  stroke: rgba(58, 50, 38, 0.22) !important;
}

/* Remap dark-mode neon accent text — class form */
.paper-mode-active [class*="text-[#43d6b5]"],
.paper-mode-active [class*="text-[#7fe5cb]"] { color: var(--teal) !important; }
.paper-mode-active [class*="text-[#f5b95f]"],
.paper-mode-active [class*="text-[#f5d9a8]"] { color: var(--gold) !important; }
.paper-mode-active [class*="text-[#ff7a5c]"],
.paper-mode-active [class*="text-[#ff9a80]"],
.paper-mode-active [class*="text-[#ffe3d7]"],
.paper-mode-active [class*="text-[#ffb09b]"] { color: var(--ember) !important; }
.paper-mode-active [class*="text-[#a78bfa]"],
.paper-mode-active [class*="text-[#bfa8f5]"] { color: var(--violet) !important; }
.paper-mode-active [class*="text-[#5ba4cf]"] { color: var(--blue) !important; }
.paper-mode-active [class*="text-[#22d3ee]"],
.paper-mode-active [class*="text-[#7fd0e8]"] { color: var(--cyan) !important; }
.paper-mode-active [class*="text-[#a3e635]"] { color: var(--lime) !important; }
.paper-mode-active [class*="text-[#f87171]"] { color: var(--ember) !important; }

/* Remap dark-mode neon accent text — inline-style form (difficulty pills, eyebrows, viz) */
.paper-mode-active [style*="color:#43d6b5"],
.paper-mode-active [style*="color:#7fe5cb"] { color: var(--teal) !important; }
.paper-mode-active [style*="color:#f5b95f"],
.paper-mode-active [style*="color:#f5d9a8"] { color: var(--gold) !important; }
.paper-mode-active [style*="color:#ff7a5c"],
.paper-mode-active [style*="color:#ff9a80"],
.paper-mode-active [style*="color:#ffe3d7"],
.paper-mode-active [style*="color:#ffb09b"] { color: var(--ember) !important; }
.paper-mode-active [style*="color:#a78bfa"],
.paper-mode-active [style*="color:#bfa8f5"] { color: var(--violet) !important; }
.paper-mode-active [style*="color:#5ba4cf"] { color: var(--blue) !important; }
.paper-mode-active [style*="color:#22d3ee"],
.paper-mode-active [style*="color:#7fd0e8"] { color: var(--cyan) !important; }
.paper-mode-active [style*="color:#a3e635"] { color: var(--lime) !important; }
.paper-mode-active [style*="color:#f87171"] { color: var(--ember) !important; }

/* Remap dark-mode accent fills — class & style form (difficulty pills, chips) */
.paper-mode-active [class*="bg-[#43d6b5]"],
.paper-mode-active [style*="background:#43d6b5"] { background-color: rgba(15, 107, 96, 0.12) !important; }
.paper-mode-active [class*="bg-[#f5b95f]"],
.paper-mode-active [style*="background:#f5b95f"] { background-color: rgba(154, 100, 16, 0.12) !important; }
.paper-mode-active [class*="bg-[#ff7a5c]"],
.paper-mode-active [style*="background:#ff7a5c"] { background-color: rgba(192, 54, 29, 0.12) !important; }
.paper-mode-active [class*="bg-[#bfa8f5]"],
.paper-mode-active [style*="background:#bfa8f5"] { background-color: rgba(91, 63, 181, 0.12) !important; }

/* Code blocks & Markdown in Paper Mode */
.paper-mode-active pre {
  background: var(--code-bg) !important;
  border: 1px solid var(--code-border) !important;
  color: #2b2620 !important;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.55),
              0 1px 2px rgba(60, 50, 40, 0.05) !important;
}
.paper-mode-active pre code {
  color: #2b2620 !important;
}
.paper-mode-active code {
  background: var(--code-bg) !important;
  color: var(--gold) !important;
  border: 1px solid var(--code-border) !important;
}
.paper-mode-active blockquote {
  border-left-color: var(--gold) !important;
  color: #4a423a !important;
}
.paper-mode-active table {
  border-color: var(--border) !important;
}
.paper-mode-active th,
.paper-mode-active td {
  border-color: var(--border) !important;
}

/* Top Bar & Navigation in Paper Mode */
.paper-mode-active header {
  background: linear-gradient(to bottom, rgba(238, 232, 221, 0.96), rgba(238, 232, 221, 0.75), transparent) !important;
}
.paper-mode-active header .display {
  color: var(--ink) !important;
}
.paper-mode-active nav {
  background: rgba(45, 41, 38, 0.06) !important;
}
.paper-mode-active nav a {
  color: var(--muted) !important;
}
.paper-mode-active nav a:hover {
  background: rgba(45, 41, 38, 0.09) !important;
  color: var(--ink) !important;
}
.paper-mode-active nav a.bg-\[\#f4f1e9\] {
  background: var(--ink) !important;
  color: var(--background) !important;
  box-shadow: 0 4px 16px rgba(28, 26, 23, 0.2) !important;
}

/* Buttons & Inputs in Paper Mode */
.paper-mode-active .btn-primary {
  background: var(--ink) !important;
  color: var(--background) !important;
  box-shadow: 0 6px 20px rgba(28, 26, 23, 0.18) !important;
}
.paper-mode-active .btn-primary:hover:not(:disabled) {
  background: #39332d !important;
  box-shadow: 0 10px 28px rgba(28, 26, 23, 0.28) !important;
}
.paper-mode-active .btn-ghost {
  background: rgba(45, 41, 38, 0.06) !important;
  color: var(--ink) !important;
}
.paper-mode-active .btn-ghost:hover:not(:disabled) {
  background: rgba(45, 41, 38, 0.12) !important;
}
.paper-mode-active .input {
  background: var(--code-bg) !important;
  border-color: var(--border) !important;
  color: var(--ink) !important;
}
.paper-mode-active .input::placeholder {
  color: var(--faint) !important;
}
.paper-mode-active .input:focus {
  background: var(--surface) !important;
  border-color: var(--gold) !important;
  box-shadow: 0 0 0 4px rgba(154, 100, 16, 0.15) !important;
}

.paper-mode-active ::selection {
  background: rgba(154, 100, 16, 0.25);
  color: var(--ink);
}

@media (prefers-reduced-motion: reduce) {
  body {
    transition: background-color 300ms ease, color 300ms ease;
  }
}

"use client";

import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { Suspense, useCallback, useEffect, useRef, useState } from "react";
import Nav from "@/components/Nav";
import ReportCardView, { KIND_LABEL } from "@/components/ReportCardView";
import QuestionWidget from "@/components/QuestionWidget";
import { demoQuestionBank } from "@/lib/demo";
import {
  finishQuiz,
  getPlan,
  markPlanCompleted,
  saveQuizAnswer,
  startQuiz,
  getTodayReviewDetail,
  getLatestReportToday,
} from "@/lib/data";
import { getAllStorySections } from "@/lib/stories";
import type {
  DailyPlan,
  PlanItem,
  QuizSession,
  ReportCard,
  SessionQuestion,
} from "@/lib/types";
import { categoryColor } from "@/lib/types";

const SERIES_TITLES: Record<string, string> = {
  "competition-act": "Legal Series",
  "dsa": "DSA Series",
  "sql": "SQL Series",
  "psychopaths-and-savages": "Psychology Series",
  "general": "General Knowledge",
};

const SERIES_COLORS: Record<string, string> = {
  "competition-act": "#5ba4cf",
  "dsa": "#f5b95f",
  "sql": "#22d3ee",
  "psychopaths-and-savages": "#d94f5c",
  "general": "#9aa0aa",
};

/** On-brand section header for a review group (colour-coded per series). */
function GroupHeader({ slug }: { slug: string }) {
  const color = SERIES_COLORS[slug] ?? "#9aa0aa";
  return (
    <div className="flex items-center gap-2.5 border-b border-white/[0.08] pb-2.5">
      <span
        className="h-2 w-2 shrink-0 rounded-full"
        style={{ background: color, boxShadow: `0 0 8px ${color}` }}
      />
      <h2 className="text-xs font-bold uppercase tracking-[0.14em]" style={{ color }}>
        {SERIES_TITLES[slug] ?? slug}
      </h2>
    </div>
  );
}

export default function ReviewPage() {
  return (
    <Suspense fallback={<ReviewFallback />}>
      <ReviewRunner />
    </Suspense>
  );
}

function ReviewFallback() {
  return (
    <>
      <Nav />
      <main className="mx-auto w-full max-w-2xl flex-1 px-4 pb-28 pt-8 sm:px-6 md:pb-16">
        <div className="glass rise flex items-center justify-center gap-3 p-16 text-muted">
          <Spinner /> Preparing your next challenge…
        </div>
      </main>
    </>
  );
}

function ReviewRunner() {
  const searchParams = useSearchParams();
  const seriesParam = searchParams.get("series");
  const topicId = searchParams.get("topic"); // Legacy deep link support

  const [plan, setPlan] = useState<DailyPlan | null>(null);
  const [session, setSession] = useState<QuizSession | null>(null);
  const [phase, setPhase] = useState<"loading" | "quizzing" | "finishing" | "report" | "finished" | "empty">("loading");

  const [groupedItems, setGroupedItems] = useState<Map<string, PlanItem[]>>(new Map());
  const [completedGroups, setCompletedGroups] = useState<Set<string>>(new Set());

  const [groupedReports, setGroupedReports] = useState<Map<string, ReportCard>>(new Map());

  const [error, setError] = useState<string | null>(null);
  const [singleTask, setSingleTask] = useState(false);

  useEffect(() => {
    let cancelled = false;
    setPhase("loading");
    setError(null);
    setCompletedGroups(new Set());

    Promise.all([getPlan(), getAllStorySections()])
      .then(async ([full, sections]) => {
        if (cancelled) return;

        const seriesByTopicId = new Map<string, string>();
        for (const s of sections) {
          if (s.topic_id) seriesByTopicId.set(s.topic_id, s.series_slug);
        }

        // Handle full report check
        if (full.completed && !topicId && !seriesParam) {
          try {
            const latestReport = await getLatestReportToday();
            if (latestReport) {
              if (cancelled) return;
              groupAndSetReport(latestReport, seriesByTopicId);
              setPhase("report");
              return;
            }
          } catch {}
        }

        let p: DailyPlan = full;
        const isMatched = !!topicId && full.items.some(it => it.topic_id === topicId);

        if (isMatched) {
          p = { ...full, items: full.items.filter((it) => it.topic_id === topicId) };
          setSingleTask(true);
        } else if (seriesParam) {
          if (seriesParam === "general") {
            p = { ...full, items: full.items.filter(it => !seriesByTopicId.get(it.topic_id)) };
          } else {
            p = { ...full, items: full.items.filter(it => seriesByTopicId.get(it.topic_id) === seriesParam) };
          }
          setSingleTask(true); // Don't complete the full day if just doing one series
        } else {
          // Normal run: sort pending first
          p = { ...full, items: [...full.items].sort((a, b) => Number(!!a.done) - Number(!!b.done)) };
          setSingleTask(false);
        }

        setPlan(p);
        if (p.items.length === 0) {
          setPhase("empty");
          return;
        }

        // Group items
        const groups = new Map<string, PlanItem[]>();
        for (const item of p.items) {
          const slug = seriesByTopicId.get(item.topic_id) || "general";
          if (!groups.has(slug)) groups.set(slug, []);
          groups.get(slug)!.push(item);
        }
        setGroupedItems(groups);

        const pendingIds = p.items.filter(it => !it.done).map(it => it.topic_id);
        let quiz: QuizSession | null = null;
        if (pendingIds.length > 0) {
          try {
            quiz = await startQuiz(pendingIds);
          } catch (e) {
            if (!cancelled) {
              setError(e instanceof Error ? e.message : "Couldn't start the quiz session");
              // Even if it failed, we can still show 'already done' items if any,
              // but if all are pending, it's an error.
            }
          }
        }

        if (cancelled) return;
        setSession(quiz);
        setPhase("quizzing");
      })
      .catch((e) => {
        if (!cancelled) {
          setError("Failed to load plan.");
          setPhase("empty");
        }
      });

    return () => { cancelled = true; };
  }, [seriesParam, topicId]);

  function groupAndSetReport(rep: ReportCard, seriesByTopicId: Map<string, string>) {
    const groups = new Map<string, ReportCard>();
    for (const item of rep.items) {
      const slug = seriesByTopicId.get(item.topic_id) || "general";
      if (!groups.has(slug)) {
        groups.set(slug, { ...rep, items: [], score_pct: 0, strengths: [], focus: [] });
      }
      groups.get(slug)!.items.push(item);
    }

    // Recalculate score per group
    for (const [slug, group] of Array.from(groups.entries())) {
      group.score_pct = Math.round(group.items.reduce((acc, it) => acc + (it.score || 0), 0) / group.items.length * 20);
      group.strengths = group.items.filter(it => (it.score || 0) >= 4).map(it => it.topic_name);
      group.focus = group.items.filter(it => (it.score || 0) < 4).map(it => it.topic_name);
    }

    setGroupedReports(groups);
  }

  const handleGroupComplete = useCallback(async (slug: string, answeredCount: number) => {
    setCompletedGroups(prev => {
      const next = new Set(prev);
      next.add(slug);
      return next;
    });
  }, []);

  // Watch for all groups completed
  useEffect(() => {
    if (phase !== "quizzing") return;
    if (groupedItems.size === 0) return;
    if (completedGroups.size === groupedItems.size) {
      finalize();
    }
  }, [completedGroups, groupedItems, phase]);

  async function finalize() {
    setPhase("finishing");
    try {
      if (session) {
        const r = await finishQuiz(session.id);
        const sections = await getAllStorySections();
        const seriesByTopicId = new Map<string, string>();
        for (const s of sections) {
          if (s.topic_id) seriesByTopicId.set(s.topic_id, s.series_slug);
        }
        groupAndSetReport(r, seriesByTopicId);
        setPhase("report");
      } else {
        setPhase("finished"); // all were already done
      }

      if (!singleTask) {
        try {
          const p = await getPlan();
          if (p.items.length > 0 && p.items.every(it => it.done) && !p.completed) {
            await markPlanCompleted();
          }
        } catch {}
      }
    } catch (e) {
      setError(e instanceof Error ? e.message : "Couldn't build your report card");
      setPhase("finished");
    }
  }

  return (
    <>
      <Nav />
      <main className="mx-auto w-full max-w-2xl flex-1 px-4 pb-28 pt-8 sm:px-6 md:pb-16">
        {phase === "empty" && (
          <div className="glass rise p-8 text-center">
            <h1 className="mb-2 text-xl font-bold">Nothing to revise yet</h1>
            <p className="mb-5 text-muted">{error || "Log some learnings first and come back."}</p>
            <Link href="/" className="btn-primary">Go to Dashboard</Link>
          </div>
        )}

        {phase === "loading" && (
          <div className="glass rise flex items-center justify-center gap-3 p-16 text-muted">
            <Spinner /> Preparing your next challenge…
          </div>
        )}

        {phase === "finishing" && (
          <div className="glass rise flex flex-col items-center justify-center gap-3 p-16 text-muted">
            <Spinner />
            <p className="font-medium text-white/85">Building your report card…</p>
            <p className="text-sm">One pass over all your answers — grading, feedback, the lot.</p>
          </div>
        )}

        {phase === "quizzing" && plan && (
          <div className="space-y-12 rise">
            {error && !session && <p className="text-danger text-center">{error}</p>}

            {Array.from(groupedItems.entries()).map(([slug, items]) => (
              <div key={slug} className="space-y-4">
                {groupedItems.size > 1 && <GroupHeader slug={slug} />}

                {completedGroups.has(slug) ? (
                  <div className="glass rise p-8 text-center">
                    <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-full bg-[#43d6b5]/[0.12] text-xl text-[#43d6b5]">
                      ✓
                    </div>
                    <h3 className="text-lg font-bold">Section Complete</h3>
                    <p className="text-sm text-muted">You have finished {SERIES_TITLES[slug] ?? slug} for today.</p>
                  </div>
                ) : (
                  <QuizCarousel
                    items={items}
                    session={session}
                    onComplete={(ansCount) => handleGroupComplete(slug, ansCount)}
                  />
                )}
              </div>
            ))}
          </div>
        )}

        {phase === "report" && (
          <div className="space-y-12 rise">
            {Array.from(groupedReports.entries()).map(([slug, rep]) => (
              <div key={slug} className="space-y-6">
                {groupedReports.size > 1 && <GroupHeader slug={slug} />}
                <ReportCardView report={rep} />
              </div>
            ))}

            <div className="mt-8 flex flex-wrap justify-center gap-3">
              <Link href="/" className="btn-primary">Back to dashboard</Link>
              <Link href="/brain" className="btn-ghost">Explore your brain</Link>
            </div>
          </div>
        )}

        {phase === "finished" && (
          <div className="glass rise p-10 text-center">
            <div className="mx-auto mb-5 flex h-20 w-20 items-center justify-center rounded-full bg-gradient-to-br from-[#ff7a5c] to-[#f5b95f] text-4xl shadow-[0_0_50px_rgba(255,122,92,0.5)]">

            </div>
            <h1 className="mb-2 text-2xl font-bold">Session complete!</h1>
            {error && <p className="mb-3 text-sm text-danger">{error}</p>}
            <p className="mb-8 text-muted">
              Every recall today just made the forgetting curve flatter.
            </p>
            <div className="flex flex-wrap justify-center gap-3">
              <Link href="/" className="btn-primary">Back to dashboard</Link>
              <Link href="/brain" className="btn-ghost">Explore your brain</Link>
            </div>
          </div>
        )}
      </main>
    </>
  );
}

function QuizCarousel({
  items,
  session,
  onComplete,
}: {
  items: PlanItem[];
  session: QuizSession | null;
  onComplete: (answeredCount: number) => void;
}) {
  const [index, setIndex] = useState(0);
  const [phase, setPhase] = useState<"loading" | "question" | "already-done">("loading");

  const [question, setQuestion] = useState<SessionQuestion | null>(null);
  const [answer, setAnswer] = useState("");
  const [selected, setSelected] = useState<number | null>(null);
  const [multiSelected, setMultiSelected] = useState<number[]>([]);
  const [saving, setSaving] = useState(false);
  const [answeredCount, setAnsweredCount] = useState(0);

  const [error, setError] = useState<string | null>(null);
  const [doneDetail, setDoneDetail] = useState<{
    question: string;
    userAnswer: string;
    storedAnswer: string;
    feedback?: string;
  } | null>(null);

  const item = items[index];

  const loadItem = useCallback(async (i: number) => {
    const it = items[i];
    if (!it) return;

    setError(null);
    setAnswer("");
    setSelected(null);
    setMultiSelected([]);
    setQuestion(null);
    setDoneDetail(null);

    if (it.done) {
      setPhase("loading");
      try {
        const detail = await getTodayReviewDetail(it.topic_id);
        if (detail) {
          setDoneDetail(detail);
        }
      } catch { /* fallback */ }
      setPhase("already-done");
      return;
    }

    setPhase("loading");

    const bankQuestion = session?.questions.find((q) => q.topic_id === it.topic_id) ?? null;

    if (bankQuestion) {
      setQuestion(bankQuestion);
      setPhase("question");
    } else {
      setError("No question available for this topic yet — add more learnings to grow the bank.");
      setPhase("question");
    }
  }, [items, session]);

  useEffect(() => {
    loadItem(0);
  }, [loadItem]);

  function next() {
    if (index + 1 < items.length) {
      setIndex(index + 1);
      loadItem(index + 1);
    } else {
      onComplete(answeredCount);
    }
  }

  async function submitCurrent(skip = false) {
    if (!question || !session || saving) return;
    setSaving(true);
    setError(null);

    const isSingleChoice = question.kind === "mcq" || question.kind === "truefalse";
    const isMulti = question.kind === "multi";

    try {
      await saveQuizAnswer({
        sessionId: session.id,
        questionIndex: question.index,
        answer: isSingleChoice || isMulti ? undefined : skip ? "" : answer,
        selectedIndex: isSingleChoice && !skip ? selected ?? undefined : undefined,
        selectedIndices: isMulti && !skip && multiSelected.length ? [...multiSelected].sort((a, b) => a - b) : undefined,
      });
      setAnsweredCount(c => c + 1);
      setSaving(false);
      next();
    } catch (e) {
      setSaving(false);
      setError(e instanceof Error ? e.message : "Couldn't save your answer");
    }
  }

  function toggleMulti(i: number) {
    setMultiSelected((cur) => cur.includes(i) ? cur.filter((x) => x !== i) : [...cur, i]);
  }

  const canSubmit = !!question && (question.kind === "mcq" || question.kind === "truefalse"
    ? selected !== null
    : question.kind === "multi" ? multiSelected.length > 0 : answer.trim().length > 0);

  const pendingCount = items.filter(it => !it.done).length;
  const progress = items.length ? (index / items.length) * 100 : 0;

  if (!item) return null;

  return (
    <div className="space-y-4">
      {/* Progress bar */}
      <div className="rise mb-4">
        <div className="mb-2 flex items-center justify-between text-sm">
          <span className="text-muted">
            {index + 1} of {items.length}
            {pendingCount < items.length && (
              <span className="ml-2 text-xs opacity-60">· {pendingCount} to answer</span>
            )}
          </span>
          <span className="micro !text-[#f5b95f]">
            Answers are graded together at the end
          </span>
        </div>
        <div className="h-2 overflow-hidden rounded-full bg-white/[0.06]">
          <div
            className="h-full rounded-full bg-gradient-to-r from-[#ff7a5c] to-[#f5b95f] transition-all duration-500"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {phase === "loading" && (
        <div className="glass rise flex items-center justify-center gap-3 p-16 text-muted">
          <Spinner />
        </div>
      )}

      {/* Topic header */}
      {["question", "already-done"].includes(phase) && (
        <div className="rise mb-4 flex items-center gap-2.5">
          <span
            className="h-2.5 w-2.5 rounded-full"
            style={{ background: categoryColor(item.category), boxShadow: `0 0 8px ${categoryColor(item.category)}` }}
          />
          <span className="font-semibold">{item.topic_name}</span>
          <span className="micro rounded-full bg-white/[0.05] px-3 py-1">
            {phase === "already-done" ? "Done today" : KIND_LABEL[question?.kind ?? "open"]}
          </span>
          {item.done && (
            <span className="micro ml-auto rounded-full bg-[#43d6b5]/[0.12] px-3 py-1 text-[#7fe5cb]">
              ✓ Reviewed
            </span>
          )}
        </div>
      )}

      {/* Already-done card */}
      {phase === "already-done" && (
        <div className="glass rise p-6 space-y-6">
          <div className="text-center">
            <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-full bg-[#43d6b5]/[0.12] text-xl text-[#43d6b5]">✓</div>
            <h2 className="text-lg font-bold">Already reviewed today</h2>
            <p className="text-xs text-muted">Here is your attempt from earlier today.</p>
          </div>

          {doneDetail ? (
            <div className="space-y-4">
              <div className="rounded-xl bg-white/[0.02] p-4 border border-white/[0.04]">
                <p className="micro mb-1.5 !text-faint">Question Prompt</p>
                <p className="text-sm font-medium leading-relaxed text-white/90">{doneDetail.question}</p>
              </div>
              <div className="rounded-xl bg-white/[0.03] p-4 border border-white/[0.05]">
                <p className="micro mb-1.5 !text-[#ff9a80]">Your Answer</p>
                <p className="text-sm leading-relaxed text-white/80">{doneDetail.userAnswer}</p>
              </div>
              <div className="rounded-xl bg-[#43d6b5]/[0.04] p-4 border border-[#43d6b5]/[0.08]">
                <p className="micro mb-1.5 !text-[#43d6b5]">Stored Model Answer</p>
                <p className="text-sm leading-relaxed text-muted">{doneDetail.storedAnswer}</p>
              </div>
              {doneDetail.feedback && (
                <div className="rounded-xl bg-[#f5b95f]/[0.04] p-4 border border-[#f5b95f]/[0.08]">
                  <p className="micro mb-1.5 !text-[#f5b95f]">Feedback</p>
                  <p className="text-sm leading-relaxed text-muted">{doneDetail.feedback}</p>
                </div>
              )}
            </div>
          ) : (
            <p className="text-center text-sm text-muted">You covered <span className="font-semibold text-white/85">{item.topic_name}</span> earlier.</p>
          )}
          <div className="flex justify-center pt-2">
            <button className="btn-primary" onClick={next}>
              {index + 1 < items.length ? "Next topic →" : "Finish section →"}
            </button>
          </div>
        </div>
      )}

      {/* Question */}
      {phase === "question" && question && (
        <div className="glass rise p-6">
          <p className="mb-5 text-lg font-medium leading-relaxed">{question.prompt}</p>

          {question.kind === "truefalse" && question.options ? (
            <div className="grid grid-cols-2 gap-4">
              {question.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => setSelected(i)}
                  disabled={saving}
                  className={`rounded-2xl border py-4 text-center text-base font-bold transition-all ${
                    selected === i
                      ? "border-[#f5b95f]/60 bg-[#f5b95f]/[0.1] text-white"
                      : "border-white/[0.07] bg-white/[0.03] text-white/80 hover:border-white/[0.15] hover:bg-white/[0.05]"
                  }`}
                >
                  {opt}
                </button>
              ))}
            </div>
          ) : question.kind === "mcq" && question.options ? (
            <div className="space-y-2.5">
              {question.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => setSelected(i)}
                  disabled={saving}
                  className={`block w-full rounded-2xl border px-4 py-3.5 text-left text-[15px] leading-relaxed transition-all ${
                    selected === i
                      ? "border-[#f5b95f]/60 bg-[#f5b95f]/[0.1] text-white"
                      : "border-white/[0.07] bg-white/[0.03] text-white/80 hover:border-white/[0.15] hover:bg-white/[0.05]"
                  }`}
                >
                  <span className="mr-3 inline-flex h-6 w-6 items-center justify-center rounded-full bg-white/[0.07] text-xs font-bold">
                    {String.fromCharCode(65 + i)}
                  </span>
                  {opt}
                </button>
              ))}
            </div>
          ) : question.kind === "multi" && question.options ? (
            <div className="space-y-2.5">
              <p className="micro !text-[#f5b95f]">Select all that apply</p>
              {question.options.map((opt, i) => {
                const picked = multiSelected.includes(i);
                return (
                  <button
                    key={i}
                    onClick={() => toggleMulti(i)}
                    disabled={saving}
                    className={`block w-full rounded-2xl border px-4 py-3.5 text-left text-[15px] leading-relaxed transition-all ${
                      picked
                        ? "border-[#f5b95f]/60 bg-[#f5b95f]/[0.1] text-white"
                        : "border-white/[0.07] bg-white/[0.03] text-white/80 hover:border-white/[0.15] hover:bg-white/[0.05]"
                    }`}
                  >
                    <span className={`mr-3 inline-flex h-6 w-6 items-center justify-center rounded-lg text-xs font-bold ${picked ? "bg-[#f5b95f] text-[#1a120e]" : "bg-white/[0.07]"}`}>
                      {picked ? "✓" : String.fromCharCode(65 + i)}
                    </span>
                    {opt}
                  </button>
                );
              })}
            </div>
          ) : (
            <textarea
              className="input min-h-[140px] resize-y"
              placeholder="Answer from memory — no peeking."
              value={answer}
              onChange={(e) => setAnswer(e.target.value)}
              disabled={saving}
            />
          )}

          {error && <p className="mt-3 text-sm text-danger">{error}</p>}
          <div className="mt-4 flex justify-between">
            <button className="btn-ghost text-sm" onClick={() => submitCurrent(true)} disabled={saving}>Skip</button>
            <button className="btn-primary" onClick={() => submitCurrent(false)} disabled={saving || !canSubmit}>
              {saving ? <><Spinner /> Saving…</> : index + 1 < items.length ? "Save & next →" : "Save section →"}
            </button>
          </div>
        </div>
      )}

      {phase === "question" && !question && (
        <div className="glass rise p-8 text-center">
          <h2 className="mb-2 text-lg font-bold">Couldn&apos;t load this question</h2>
          <p className="mb-6 text-sm text-danger">{error ?? "Something went wrong."}</p>
          <button className="btn-ghost text-sm" onClick={next}>Skip this topic</button>
        </div>
      )}
    </div>
  );
}

function Spinner() {
  return (
    <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
      <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" opacity="0.25" />
      <path d="M22 12a10 10 0 0 0-10-10" stroke="currentColor" strokeWidth="3" strokeLinecap="round" />
    </svg>
  );
}

"use client";

import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { Suspense, useCallback, useEffect, useRef, useState } from "react";
import Nav from "@/components/Nav";
import ReportCardView, { KIND_LABEL } from "@/components/ReportCardView";
import {
  finishQuiz,
  getPlan,
  markPlanCompleted,
  saveQuizAnswer,
  startQuiz,
  getTodayReviewDetail,
  getLatestReportToday,
} from "@/lib/data";
import { getAllStorySections } from "@/lib/stories";
import type {
  DailyPlan,
  PlanItem,
  QuizSession,
  ReportCard,
  SessionQuestion,
} from "@/lib/types";
import { categoryColor } from "@/lib/types";

const SERIES_TITLES: Record<string, string> = {
  "competition-act": "Legal Series",
  "dsa": "DSA Series",
  "sql": "SQL Series",
  "psychopaths-and-savages": "Psychology Series",
  "general": "General Knowledge",
};

const SERIES_COLORS: Record<string, string> = {
  "competition-act": "#5ba4cf",
  "dsa": "#f5b95f",
  "sql": "#22d3ee",
  "psychopaths-and-savages": "#d94f5c",
  "general": "#9aa0aa",
};

/** On-brand section header for a review group (colour-coded per series). */
function GroupHeader({ slug }: { slug: string }) {
  const color = SERIES_COLORS[slug] ?? "#9aa0aa";
  return (
    <div className="flex items-center gap-2.5 border-b border-white/[0.08] pb-2.5">
      <span
        className="h-2 w-2 shrink-0 rounded-full"
        style={{ background: color, boxShadow: `0 0 8px ${color}` }}
      />
      <h2 className="text-xs font-bold uppercase tracking-[0.14em]" style={{ color }}>
        {SERIES_TITLES[slug] ?? slug}
      </h2>
    </div>
  );
}

export default function ReviewPage() {
  return (
    <Suspense fallback={<ReviewFallback />}>
      <ReviewRunner />
    </Suspense>
  );
}

function ReviewFallback() {
  return (
    <>
      <Nav />
      <main className="mx-auto w-full max-w-2xl flex-1 px-4 pb-28 pt-8 sm:px-6 md:pb-16">
        <div className="glass rise flex items-center justify-center gap-3 p-16 text-muted">
          <Spinner /> Preparing your next challenge…
        </div>
      </main>
    </>
  );
}

function ReviewRunner() {
  const searchParams = useSearchParams();
  const seriesParam = searchParams.get("series");
  const topicId = searchParams.get("topic"); // Legacy deep link support

  const [phase, setPhase] = useState<"loading" | "quizzing" | "report" | "empty">("loading");

  // Live flow: each series group runs its OWN independent session so a report
  // card appears the moment THAT section is submitted (topic-wise reports).
  const [groupedItems, setGroupedItems] = useState<Map<string, PlanItem[]>>(new Map());
  const [sessionsByGroup, setSessionsByGroup] = useState<Map<string, QuizSession | null>>(new Map());
  const [completedGroups, setCompletedGroups] = useState<Set<string>>(new Set());

  // Revisit flow: day already done → show the merged report, grouped by series.
  const [groupedReports, setGroupedReports] = useState<Map<string, ReportCard>>(new Map());

  const [error, setError] = useState<string | null>(null);
  const [singleTask, setSingleTask] = useState(false);

  useEffect(() => {
    let cancelled = false;
    setPhase("loading");
    setError(null);
    setCompletedGroups(new Set());
    setGroupedReports(new Map());

    Promise.all([getPlan(), getAllStorySections()])
      .then(async ([full, sections]) => {
        if (cancelled) return;

        const seriesByTopicId = new Map<string, string>();
        for (const s of sections) {
          if (s.topic_id) seriesByTopicId.set(s.topic_id, s.series_slug);
        }

        // Revisit: whole day already complete → show grouped merged report
        if (full.completed && !topicId && !seriesParam) {
          try {
            const latestReport = await getLatestReportToday();
            if (latestReport) {
              if (cancelled) return;
              groupAndSetReport(latestReport, seriesByTopicId);
              setPhase("report");
              return;
            }
          } catch {}
        }

        let p: DailyPlan = full;
        const isMatched = !!topicId && full.items.some((it) => it.topic_id === topicId);

        if (isMatched) {
          p = { ...full, items: full.items.filter((it) => it.topic_id === topicId) };
          setSingleTask(true);
        } else if (seriesParam) {
          if (seriesParam === "general") {
            p = { ...full, items: full.items.filter((it) => !seriesByTopicId.get(it.topic_id)) };
          } else {
            p = { ...full, items: full.items.filter((it) => seriesByTopicId.get(it.topic_id) === seriesParam) };
          }
          setSingleTask(true); // Don't complete the full day if just doing one series
        } else {
          // Normal run: sort pending first
          p = { ...full, items: [...full.items].sort((a, b) => Number(!!a.done) - Number(!!b.done)) };
          setSingleTask(false);
        }

        if (p.items.length === 0) {
          setPhase("empty");
          return;
        }

        // Group items by series
        const groups = new Map<string, PlanItem[]>();
        for (const item of p.items) {
          const slug = seriesByTopicId.get(item.topic_id) || "general";
          if (!groups.has(slug)) groups.set(slug, []);
          groups.get(slug)!.push(item);
        }

        // Start an independent session per group (its pending topics only), so
        // each section can be finished + graded on its own.
        const sessions = new Map<string, QuizSession | null>();
        for (const [slug, items] of Array.from(groups.entries())) {
          const pendingIds = items.filter((it) => !it.done).map((it) => it.topic_id);
          if (pendingIds.length === 0) {
            sessions.set(slug, null);
            continue;
          }
          try {
            sessions.set(slug, await startQuiz(pendingIds));
          } catch (e) {
            sessions.set(slug, null);
            if (!cancelled) setError(e instanceof Error ? e.message : "Couldn't start a quiz session");
          }
        }

        if (cancelled) return;
        setGroupedItems(groups);
        setSessionsByGroup(sessions);
        setPhase("quizzing");
      })
      .catch(() => {
        if (!cancelled) {
          setError("Failed to load plan.");
          setPhase("empty");
        }
      });

    return () => {
      cancelled = true;
    };
  }, [seriesParam, topicId]);

  function groupAndSetReport(rep: ReportCard, seriesByTopicId: Map<string, string>) {
    const groups = new Map<string, ReportCard>();
    for (const item of rep.items) {
      const slug = seriesByTopicId.get(item.topic_id) || "general";
      if (!groups.has(slug)) {
        groups.set(slug, { ...rep, items: [], score_pct: 0, strengths: [], focus: [] });
      }
      groups.get(slug)!.items.push(item);
    }

    // Recalculate score per group
    for (const [, group] of Array.from(groups.entries())) {
      group.score_pct = Math.round((group.items.reduce((acc, it) => acc + (it.score || 0), 0) / group.items.length) * 20);
      group.strengths = group.items.filter((it) => (it.score || 0) >= 4).map((it) => it.topic_name);
      group.focus = group.items.filter((it) => (it.score || 0) < 4).map((it) => it.topic_name);
    }

    setGroupedReports(groups);
  }

  const handleGroupDone = useCallback((slug: string) => {
    setCompletedGroups((prev) => new Set(prev).add(slug));
  }, []);

  const allGroupsDone = groupedItems.size > 0 && completedGroups.size >= groupedItems.size;

  // Close the day once every group is finished (full-plan runs only).
  useEffect(() => {
    if (phase !== "quizzing" || singleTask || !allGroupsDone) return;
    (async () => {
      try {
        const p = await getPlan();
        if (p.items.length > 0 && p.items.every((it) => it.done) && !p.completed) {
          await markPlanCompleted();
        }
      } catch {}
    })();
  }, [allGroupsDone, phase, singleTask]);

  return (
    <>
      <Nav />
      <main className="mx-auto w-full max-w-2xl flex-1 px-4 pb-28 pt-8 sm:px-6 md:pb-16">
        {phase === "empty" && (
          <div className="glass rise p-8 text-center">
            <h1 className="mb-2 text-xl font-bold">Nothing to revise yet</h1>
            <p className="mb-5 text-muted">{error || "Log some learnings first and come back."}</p>
            <Link href="/" className="btn-primary">Go to Dashboard</Link>
          </div>
        )}

        {phase === "loading" && (
          <div className="glass rise flex items-center justify-center gap-3 p-16 text-muted">
            <Spinner /> Preparing your next challenge…
          </div>
        )}

        {phase === "report" && (
          <div className="space-y-12 rise">
            {Array.from(groupedReports.entries()).map(([slug, rep]) => (
              <div key={slug} className="space-y-6">
                {groupedReports.size > 1 && <GroupHeader slug={slug} />}
                <ReportCardView report={rep} />
              </div>
            ))}

            <div className="mt-8 flex flex-wrap justify-center gap-3">
              <Link href="/" className="btn-primary">Back to dashboard</Link>
              <Link href="/brain" className="btn-ghost">Explore your brain</Link>
            </div>
          </div>
        )}

        {phase === "quizzing" && (
          <div className="space-y-12 rise">
            {error && sessionsByGroup.size === 0 && <p className="text-danger text-center">{error}</p>}

            {Array.from(groupedItems.entries()).map(([slug, items]) => (
              <GroupRunner
                key={slug}
                slug={slug}
                items={items}
                session={sessionsByGroup.get(slug) ?? null}
                showHeader={groupedItems.size > 1}
                onDone={() => handleGroupDone(slug)}
              />
            ))}

            {allGroupsDone && (
              <div className="mt-8 flex flex-wrap justify-center gap-3">
                <Link href="/" className="btn-primary">Back to dashboard</Link>
                <Link href="/brain" className="btn-ghost">Explore your brain</Link>
              </div>
            )}
          </div>
        )}
      </main>
    </>
  );
}

/**
 * One series group: runs its carousel, then finishes ITS OWN session and shows
 * ITS OWN report card inline — independent of the other groups on the page.
 */
function GroupRunner({
  slug,
  items,
  session,
  showHeader,
  onDone,
}: {
  slug: string;
  items: PlanItem[];
  session: QuizSession | null;
  showHeader: boolean;
  onDone: () => void;
}) {
  const [phase, setPhase] = useState<"quizzing" | "finishing" | "report" | "done">("quizzing");
  const [report, setReport] = useState<ReportCard | null>(null);
  const [error, setError] = useState<string | null>(null);
  const doneCalled = useRef(false);

  const notifyDone = useCallback(() => {
    if (!doneCalled.current) {
      doneCalled.current = true;
      onDone();
    }
  }, [onDone]);

  const finishGroup = useCallback(async () => {
    if (session) {
      setPhase("finishing");
      try {
        const r = await finishQuiz(session.id);
        setReport(r);
        setPhase("report");
      } catch (e) {
        setError(e instanceof Error ? e.message : "Couldn't build your report card");
        setPhase("done");
      }
    } else {
      setPhase("done"); // every item in this group was already reviewed today
    }
    notifyDone();
  }, [session, notifyDone]);

  return (
    <div className="space-y-6">
      {showHeader && <GroupHeader slug={slug} />}

      {phase === "quizzing" && (
        <QuizCarousel items={items} session={session} onComplete={finishGroup} />
      )}

      {phase === "finishing" && (
        <div className="glass rise flex flex-col items-center justify-center gap-3 p-12 text-muted">
          <Spinner />
          <p className="font-medium text-white/85">Building your report card…</p>
          <p className="text-sm">Grading this section — feedback, the lot.</p>
        </div>
      )}

      {phase === "report" && report && <ReportCardView report={report} />}

      {phase === "done" && (
        <div className="glass rise p-8 text-center">
          <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-full bg-[#43d6b5]/[0.12] text-xl text-[#43d6b5]">
            ✓
          </div>
          <h3 className="text-lg font-bold">Section complete</h3>
          {error ? (
            <p className="text-sm text-danger">{error}</p>
          ) : (
            <p className="text-sm text-muted">
              You&apos;ve finished {SERIES_TITLES[slug] ?? slug} for today.
            </p>
          )}
        </div>
      )}
    </div>
  );
}

function QuizCarousel({
  items,
  session,
  onComplete,
}: {
  items: PlanItem[];
  session: QuizSession | null;
  onComplete: () => void;
}) {
  const [index, setIndex] = useState(0);
  const [phase, setPhase] = useState<"loading" | "question" | "already-done">("loading");

  const [question, setQuestion] = useState<SessionQuestion | null>(null);
  const [answer, setAnswer] = useState("");
  const [selected, setSelected] = useState<number | null>(null);
  const [multiSelected, setMultiSelected] = useState<number[]>([]);
  const [saving, setSaving] = useState(false);

  const [error, setError] = useState<string | null>(null);
  const [doneDetail, setDoneDetail] = useState<{
    question: string;
    userAnswer: string;
    storedAnswer: string;
    feedback?: string;
  } | null>(null);

  const item = items[index];

  const loadItem = useCallback(async (i: number) => {
    const it = items[i];
    if (!it) return;

    setError(null);
    setAnswer("");
    setSelected(null);
    setMultiSelected([]);
    setQuestion(null);
    setDoneDetail(null);

    if (it.done) {
      setPhase("loading");
      try {
        const detail = await getTodayReviewDetail(it.topic_id);
        if (detail) {
          setDoneDetail(detail);
        }
      } catch { /* fallback */ }
      setPhase("already-done");
      return;
    }

    setPhase("loading");

    const bankQuestion = session?.questions.find((q) => q.topic_id === it.topic_id) ?? null;

    if (bankQuestion) {
      setQuestion(bankQuestion);
      setPhase("question");
    } else {
      setError("No question available for this topic yet — add more learnings to grow the bank.");
      setPhase("question");
    }
  }, [items, session]);

  useEffect(() => {
    loadItem(0);
  }, [loadItem]);

  function next() {
    if (index + 1 < items.length) {
      setIndex(index + 1);
      loadItem(index + 1);
    } else {
      onComplete();
    }
  }

  async function submitCurrent(skip = false) {
    if (!question || !session || saving) return;
    setSaving(true);
    setError(null);

    const isSingleChoice = question.kind === "mcq" || question.kind === "truefalse";
    const isMulti = question.kind === "multi";

    try {
      await saveQuizAnswer({
        sessionId: session.id,
        questionIndex: question.index,
        answer: isSingleChoice || isMulti ? undefined : skip ? "" : answer,
        selectedIndex: isSingleChoice && !skip ? selected ?? undefined : undefined,
        selectedIndices: isMulti && !skip && multiSelected.length ? [...multiSelected].sort((a, b) => a - b) : undefined,
      });
      setSaving(false);
      next();
    } catch (e) {
      setSaving(false);
      setError(e instanceof Error ? e.message : "Couldn't save your answer");
    }
  }

  function toggleMulti(i: number) {
    setMultiSelected((cur) => cur.includes(i) ? cur.filter((x) => x !== i) : [...cur, i]);
  }

  const canSubmit = !!question && (question.kind === "mcq" || question.kind === "truefalse"
    ? selected !== null
    : question.kind === "multi" ? multiSelected.length > 0 : answer.trim().length > 0);

  const pendingCount = items.filter((it) => !it.done).length;
  const progress = items.length ? (index / items.length) * 100 : 0;

  if (!item) return null;

  return (
    <div className="space-y-4">
      {/* Progress bar */}
      <div className="rise mb-4">
        <div className="mb-2 flex items-center justify-between text-sm">
          <span className="text-muted">
            {index + 1} of {items.length}
            {pendingCount < items.length && (
              <span className="ml-2 text-xs opacity-60">· {pendingCount} to answer</span>
            )}
          </span>
          <span className="micro !text-[#f5b95f]">
            Answers are graded together at the end
          </span>
        </div>
        <div className="h-2 overflow-hidden rounded-full bg-white/[0.06]">
          <div
            className="h-full rounded-full bg-gradient-to-r from-[#ff7a5c] to-[#f5b95f] transition-all duration-500"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {phase === "loading" && (
        <div className="glass rise flex items-center justify-center gap-3 p-16 text-muted">
          <Spinner />
        </div>
      )}

      {/* Topic header */}
      {["question", "already-done"].includes(phase) && (
        <div className="rise mb-4 flex items-center gap-2.5">
          <span
            className="h-2.5 w-2.5 rounded-full"
            style={{ background: categoryColor(item.category), boxShadow: `0 0 8px ${categoryColor(item.category)}` }}
          />
          <span className="font-semibold">{item.topic_name}</span>
          <span className="micro rounded-full bg-white/[0.05] px-3 py-1">
            {phase === "already-done" ? "Done today" : KIND_LABEL[question?.kind ?? "open"]}
          </span>
          {item.done && (
            <span className="micro ml-auto rounded-full bg-[#43d6b5]/[0.12] px-3 py-1 text-[#7fe5cb]">
              ✓ Reviewed
            </span>
          )}
        </div>
      )}

      {/* Already-done card */}
      {phase === "already-done" && (
        <div className="glass rise p-6 space-y-6">
          <div className="text-center">
            <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-full bg-[#43d6b5]/[0.12] text-xl text-[#43d6b5]">✓</div>
            <h2 className="text-lg font-bold">Already reviewed today</h2>
            <p className="text-xs text-muted">Here is your attempt from earlier today.</p>
          </div>

          {doneDetail ? (
            <div className="space-y-4">
              <div className="rounded-xl bg-white/[0.02] p-4 border border-white/[0.04]">
                <p className="micro mb-1.5 !text-faint">Question Prompt</p>
                <p className="text-sm font-medium leading-relaxed text-white/90">{doneDetail.question}</p>
              </div>
              <div className="rounded-xl bg-white/[0.03] p-4 border border-white/[0.05]">
                <p className="micro mb-1.5 !text-[#ff9a80]">Your Answer</p>
                <p className="text-sm leading-relaxed text-white/80">{doneDetail.userAnswer}</p>
              </div>
              <div className="rounded-xl bg-[#43d6b5]/[0.04] p-4 border border-[#43d6b5]/[0.08]">
                <p className="micro mb-1.5 !text-[#43d6b5]">Stored Model Answer</p>
                <p className="text-sm leading-relaxed text-muted">{doneDetail.storedAnswer}</p>
              </div>
              {doneDetail.feedback && (
                <div className="rounded-xl bg-[#f5b95f]/[0.04] p-4 border border-[#f5b95f]/[0.08]">
                  <p className="micro mb-1.5 !text-[#f5b95f]">Feedback</p>
                  <p className="text-sm leading-relaxed text-muted">{doneDetail.feedback}</p>
                </div>
              )}
            </div>
          ) : (
            <p className="text-center text-sm text-muted">You covered <span className="font-semibold text-white/85">{item.topic_name}</span> earlier.</p>
          )}
          <div className="flex justify-center pt-2">
            <button className="btn-primary" onClick={next}>
              {index + 1 < items.length ? "Next topic →" : "Finish section →"}
            </button>
          </div>
        </div>
      )}

      {/* Question */}
      {phase === "question" && question && (
        <div className="glass rise p-6">
          <p className="mb-5 text-lg font-medium leading-relaxed">{question.prompt}</p>

          {question.kind === "truefalse" && question.options ? (
            <div className="grid grid-cols-2 gap-4">
              {question.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => setSelected(i)}
                  disabled={saving}
                  className={`rounded-2xl border py-4 text-center text-base font-bold transition-all ${
                    selected === i
                      ? "border-[#f5b95f]/60 bg-[#f5b95f]/[0.1] text-white"
                      : "border-white/[0.07] bg-white/[0.03] text-white/80 hover:border-white/[0.15] hover:bg-white/[0.05]"
                  }`}
                >
                  {opt}
                </button>
              ))}
            </div>
          ) : question.kind === "mcq" && question.options ? (
            <div className="space-y-2.5">
              {question.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => setSelected(i)}
                  disabled={saving}
                  className={`block w-full rounded-2xl border px-4 py-3.5 text-left text-[15px] leading-relaxed transition-all ${
                    selected === i
                      ? "border-[#f5b95f]/60 bg-[#f5b95f]/[0.1] text-white"
                      : "border-white/[0.07] bg-white/[0.03] text-white/80 hover:border-white/[0.15] hover:bg-white/[0.05]"
                  }`}
                >
                  <span className="mr-3 inline-flex h-6 w-6 items-center justify-center rounded-full bg-white/[0.07] text-xs font-bold">
                    {String.fromCharCode(65 + i)}
                  </span>
                  {opt}
                </button>
              ))}
            </div>
          ) : question.kind === "multi" && question.options ? (
            <div className="space-y-2.5">
              <p className="micro !text-[#f5b95f]">Select all that apply</p>
              {question.options.map((opt, i) => {
                const picked = multiSelected.includes(i);
                return (
                  <button
                    key={i}
                    onClick={() => toggleMulti(i)}
                    disabled={saving}
                    className={`block w-full rounded-2xl border px-4 py-3.5 text-left text-[15px] leading-relaxed transition-all ${
                      picked
                        ? "border-[#f5b95f]/60 bg-[#f5b95f]/[0.1] text-white"
                        : "border-white/[0.07] bg-white/[0.03] text-white/80 hover:border-white/[0.15] hover:bg-white/[0.05]"
                    }`}
                  >
                    <span className={`mr-3 inline-flex h-6 w-6 items-center justify-center rounded-lg text-xs font-bold ${picked ? "bg-[#f5b95f] text-[#1a120e]" : "bg-white/[0.07]"}`}>
                      {picked ? "✓" : String.fromCharCode(65 + i)}
                    </span>
                    {opt}
                  </button>
                );
              })}
            </div>
          ) : (
            <textarea
              className="input min-h-[140px] resize-y"
              placeholder="Answer from memory — no peeking."
              value={answer}
              onChange={(e) => setAnswer(e.target.value)}
              disabled={saving}
            />
          )}

          {error && <p className="mt-3 text-sm text-danger">{error}</p>}
          <div className="mt-4 flex justify-between">
            <button className="btn-ghost text-sm" onClick={() => submitCurrent(true)} disabled={saving}>Skip</button>
            <button className="btn-primary" onClick={() => submitCurrent(false)} disabled={saving || !canSubmit}>
              {saving ? <><Spinner /> Saving…</> : index + 1 < items.length ? "Save & next →" : "Save section →"}
            </button>
          </div>
        </div>
      )}

      {phase === "question" && !question && (
        <div className="glass rise p-8 text-center">
          <h2 className="mb-2 text-lg font-bold">Couldn&apos;t load this question</h2>
          <p className="mb-6 text-sm text-danger">{error ?? "Something went wrong."}</p>
          <button className="btn-ghost text-sm" onClick={next}>Skip this topic</button>
        </div>
      )}
    </div>
  );
}

function Spinner() {
  return (
    <svg className="h-4 w-4 animate-spin" viewBox="0 0 24 24" fill="none">
      <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" opacity="0.25" />
      <path d="M22 12a10 10 0 0 0-10-10" stroke="currentColor" strokeWidth="3" strokeLinecap="round" />
    </svg>
  );
}

import { Fragment, type ReactNode } from "react";
import VizBlock from "./viz/VizBlock";

/**
 * A small, dependency-free Markdown renderer — enough for personal notes:
 * headings, bold/italic/inline-code, links, ordered/unordered lists,
 * blockquotes, fenced code, horizontal rules and paragraphs. Deliberately
 * forgiving rather than spec-perfect.
 */

// Only http(s)/mailto (or scheme-less relative) links render as clickable —
// blocks javascript:/data:/vbscript: URI XSS from a pasted markdown link.
function isSafeHref(href: string): boolean {
  if (/^[/#?]/.test(href) || href.startsWith("//")) return true; // relative/protocol-relative
  const scheme = href.match(/^([a-z][a-z0-9+.-]*):/i)?.[1]?.toLowerCase();
  if (!scheme) return true; // no scheme at all — treat as relative
  return scheme === "http" || scheme === "https" || scheme === "mailto";
}

// ---- inline (bold / italic / code / links) ----
type InlineRule = {
  re: RegExp;
  render: (m: RegExpMatchArray, key: number) => ReactNode;
};

const INLINE: InlineRule[] = [
  {
    re: /`([^`]+)`/,
    render: (m, key) => (
      <code key={key} className="rounded-md bg-white/[0.08] px-1.5 py-0.5 font-mono text-[0.85em] text-[#f5b95f]">
        {m[1]}
      </code>
    ),
  },
  {
    re: /\[([^\]]+)\]\(([^)\s]+)\)/,
    render: (m, key) =>
      isSafeHref(m[2]) ? (
        <a
          key={key}
          href={m[2]}
          target="_blank"
          rel="noopener noreferrer"
          className="font-medium text-[#f5b95f] underline decoration-[#f5b95f]/40 underline-offset-2 hover:decoration-[#f5b95f]"
        >
          {m[1]}
        </a>
      ) : (
        <span key={key}>{m[1]}</span>
      ),
  },
  {
    re: /\*\*([^*]+)\*\*/,
    render: (m, key) => <strong key={key} className="font-semibold text-white">{inline(m[1], key * 97)}</strong>,
  },
  {
    re: /(?<![*\w])\*([^*\n]+)\*(?!\w)/,
    render: (m, key) => <em key={key} className="italic">{inline(m[1], key * 89)}</em>,
  },
];

function inline(text: string, keyBase = 0): ReactNode[] {
  let best: { rule: InlineRule; m: RegExpMatchArray } | null = null;
  for (const rule of INLINE) {
    const m = text.match(rule.re);
    if (m && m.index !== undefined && (!best || m.index < best.m.index!)) best = { rule, m };
  }
  if (!best) return [text];
  const { m, rule } = best;
  const start = m.index!;
  return [
    text.slice(0, start),
    rule.render(m, keyBase + start + 1),
    ...inline(text.slice(start + m[0].length), keyBase + start + 2),
  ];
}

// ---- block level ----
export default function Markdown({
  children,
  className,
  vizAccent,
  strictViz = false,
}: {
  children: string;
  className?: string;
  /** Accent colour passed through to `viz:*` diagrams (defaults per-primitive). */
  vizAccent?: string;
  /** Set by hand-authored story content — a malformed `viz:*` payload throws
   * (fails the SSG build loudly) instead of rendering an inline error card.
   * Never set for user-authored content (e.g. personal notes). */
  strictViz?: boolean;
}) {
  const lines = children.replace(/\r\n/g, "\n").split("\n");
  const blocks: ReactNode[] = [];
  let i = 0;
  let key = 0;

  while (i < lines.length) {
    const line = lines[i];

    // fenced code (and viz:* diagram blocks — same fence, an info-string tag)
    const fence = line.trim().match(/^```(\S*)/);
    if (fence) {
      const lang = fence[1] ?? "";
      const buf: string[] = [];
      i++;
      while (i < lines.length && !/^```/.test(lines[i].trim())) buf.push(lines[i++]);
      i++; // closing fence
      const content = buf.join("\n");
      if (lang.startsWith("viz:")) {
        blocks.push(<VizBlock key={key++} kind={lang.slice(4)} raw={content} accent={vizAccent} strict={strictViz} />);
      } else {
        blocks.push(
          <pre key={key++} className="my-3 overflow-x-auto rounded-xl bg-black/30 p-4 font-mono text-[0.85em] leading-relaxed text-white/85">
            <code>{content}</code>
          </pre>
        );
      }
      continue;
    }

    // blank
    if (line.trim() === "") { i++; continue; }

    // horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})$/.test(line.trim())) {
      blocks.push(<hr key={key++} className="my-5 border-white/10" />);
      i++;
      continue;
    }

    // headings
    const h = line.match(/^(#{1,6})\s+(.*)$/);
    if (h) {
      const level = h[1].length;
      const sizes = ["text-2xl", "text-xl", "text-lg", "text-base", "text-sm", "text-sm"];
      blocks.push(
        <p key={key++} className={`display mt-4 mb-2 font-bold text-white ${sizes[level - 1]}`}>
          {inline(h[2])}
        </p>
      );
      i++;
      continue;
    }

    // blockquote
    if (/^>\s?/.test(line)) {
      const buf: string[] = [];
      while (i < lines.length && /^>\s?/.test(lines[i])) buf.push(lines[i++].replace(/^>\s?/, ""));
      blocks.push(
        <blockquote key={key++} className="my-3 border-l-2 border-[#f5b95f]/50 pl-4 italic text-white/70">
          {inline(buf.join(" "))}
        </blockquote>
      );
      continue;
    }

    // ordered list
    if (/^\s*\d+\.\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) items.push(lines[i++].replace(/^\s*\d+\.\s+/, ""));
      blocks.push(
        <ol key={key++} className="my-3 ml-1 list-decimal space-y-1.5 pl-5 marker:text-faint">
          {items.map((it, j) => <li key={j} className="pl-1">{inline(it)}</li>)}
        </ol>
      );
      continue;
    }

    // unordered list
    if (/^\s*[-*+]\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*[-*+]\s+/.test(lines[i])) items.push(lines[i++].replace(/^\s*[-*+]\s+/, ""));
      blocks.push(
        <ul key={key++} className="my-3 space-y-1.5">
          {items.map((it, j) => (
            <li key={j} className="flex gap-2.5">
              <span className="mt-[0.55em] h-1 w-1 shrink-0 rounded-full bg-[#f5b95f]/70" />
              <span className="flex-1">{inline(it)}</span>
            </li>
          ))}
        </ul>
      );
      continue;
    }

    // paragraph — gather consecutive non-blank, non-block lines
    const buf: string[] = [];
    while (
      i < lines.length &&
      lines[i].trim() !== "" &&
      !/^```/.test(lines[i].trim()) &&
      !/^(#{1,6})\s+/.test(lines[i]) &&
      !/^>\s?/.test(lines[i]) &&
      !/^\s*\d+\.\s+/.test(lines[i]) &&
      !/^\s*[-*+]\s+/.test(lines[i]) &&
      !/^(-{3,}|\*{3,}|_{3,})$/.test(lines[i].trim())
    ) {
      buf.push(lines[i++]);
    }
    blocks.push(
      <p key={key++} className="my-2.5 leading-relaxed">
        {buf.map((b, j) => (
          <Fragment key={j}>
            {j > 0 && <br />}
            {inline(b)}
          </Fragment>
        ))}
      </p>
    );
  }

  return <div className={className}>{blocks}</div>;
}

import { Fragment, type ReactNode } from "react";
import VizBlock from "./viz/VizBlock";

/**
 * A small, dependency-free Markdown renderer — enough for personal notes:
 * headings, bold/italic/inline-code, links, ordered/unordered lists,
 * blockquotes, fenced code, horizontal rules and paragraphs. Deliberately
 * forgiving rather than spec-perfect.
 */

// Only http(s)/mailto (or scheme-less relative) links render as clickable —
// blocks javascript:/data:/vbscript: URI XSS from a pasted markdown link.
function isSafeHref(href: string): boolean {
  if (/^[/#?]/.test(href) || href.startsWith("//")) return true; // relative/protocol-relative
  const scheme = href.match(/^([a-z][a-z0-9+.-]*):/i)?.[1]?.toLowerCase();
  if (!scheme) return true; // no scheme at all — treat as relative
  return scheme === "http" || scheme === "https" || scheme === "mailto";
}

// ---- inline math ($…$) — lightweight LaTeX-ish renderer ----
// The hand-authored DSA/SQL content is peppered with inline math like
// `$O(N^2)$`, `$O(1)$`, `$O(N \log K)$`, `$2^N$`, `$A_{left}$`. Without this
// they render as literal `$O(1)$` text. We don't pull in KaTeX (keeps the
// zero-dependency Markdown renderer) — instead we translate the common command
// set to Unicode + real <sup>/<sub> nodes, which covers everything used here.
const MATH_SYMBOLS: [RegExp, string][] = [
  [/\\cdot/g, "·"], [/\\times/g, "×"], [/\\div/g, "÷"],
  [/\\leq|\\le\b/g, "≤"], [/\\geq|\\ge\b/g, "≥"], [/\\neq|\\ne\b/g, "≠"],
  [/\\approx/g, "≈"], [/\\equiv/g, "≡"], [/\\pm/g, "±"], [/\\mp/g, "∓"],
  [/\\infty/g, "∞"], [/\\ldots|\\cdots|\\dots/g, "…"],
  [/\\in\b/g, "∈"], [/\\notin\b/g, "∉"], [/\\forall/g, "∀"], [/\\exists/g, "∃"],
  [/\\subseteq/g, "⊆"], [/\\subset/g, "⊂"], [/\\cup/g, "∪"], [/\\cap/g, "∩"],
  [/\\emptyset|\\varnothing/g, "∅"],
  [/\\Rightarrow/g, "⇒"], [/\\Leftarrow/g, "⇐"], [/\\rightarrow|\\to\b/g, "→"], [/\\leftarrow/g, "←"],
  [/\\sum/g, "∑"], [/\\prod/g, "∏"], [/\\sqrt/g, "√"], [/\\partial/g, "∂"], [/\\nabla/g, "∇"],
  [/\\log\b/g, "log"], [/\\ln\b/g, "ln"], [/\\lg\b/g, "lg"], [/\\bmod\b/g, "mod"],
  [/\\Theta/g, "Θ"], [/\\theta/g, "θ"], [/\\Omega/g, "Ω"], [/\\omega/g, "ω"],
  [/\\alpha/g, "α"], [/\\beta/g, "β"], [/\\gamma/g, "γ"], [/\\delta/g, "δ"],
  [/\\lambda/g, "λ"], [/\\mu/g, "μ"], [/\\pi/g, "π"], [/\\sigma/g, "σ"], [/\\phi/g, "φ"],
  [/\\lfloor/g, "⌊"], [/\\rfloor/g, "⌋"], [/\\lceil/g, "⌈"], [/\\rceil/g, "⌉"],
  [/\\%/g, "%"], [/\\&/g, "&"], [/\\#/g, "#"], [/\\_/g, "_"],
  [/\\,|\\;|\\:|\\!/g, " "], [/\\ /g, " "], [/\\left|\\right/g, ""],
];

// Distinguishes an inline-math span from a stray currency pair like
// "$1 billion … $3 billion" (real in the Competition Act content). Math is
// short, and either has a math operator/command or has no internal spaces.
function looksLikeMath(content: string): boolean {
  if (content.length > 60) return false; // long → prose, not a formula
  if (/[₹]|\b(billion|million|trillion|crore|lakh|USD|INR|dollars?)\b/i.test(content)) return false;
  return /[\\^_=<>≤≥≠+\-/·×∑∏√]|O\(|Θ\(|Ω\(/.test(content) || !/\s/.test(content);
}

// Parse `^`/`_` runs (with optional {…} grouping) into <sup>/<sub> nodes.
function tokenizeScripts(s: string, keyBase: number): ReactNode[] {
  const nodes: ReactNode[] = [];
  let buf = "";
  let k = 0;
  const flush = () => { if (buf) { nodes.push(buf); buf = ""; } };
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (ch === "^" || ch === "_") {
      flush();
      let content: string;
      if (s[i + 1] === "{") {
        const end = s.indexOf("}", i + 2);
        content = end === -1 ? s.slice(i + 1) : s.slice(i + 2, end);
        i = end === -1 ? s.length : end;
      } else {
        content = s[i + 1] ?? "";
        i += 1;
      }
      content = content.replace(/[{}]/g, "");
      nodes.push(
        ch === "^"
          ? <sup key={`${keyBase}-s-${k++}`}>{content}</sup>
          : <sub key={`${keyBase}-s-${k++}`}>{content}</sub>
      );
    } else if (ch === "{" || ch === "}") {
      // drop grouping braces
    } else {
      buf += ch;
    }
  }
  flush();
  return nodes;
}

function renderMath(tex: string, keyBase: number): ReactNode {
  let s = tex;
  for (const [re, rep] of MATH_SYMBOLS) s = s.replace(re, rep);
  // \frac{a}{b} → a⁄b
  s = s.replace(/\\[dt]?frac\{([^{}]*)\}\{([^{}]*)\}/g, "$1⁄$2");
  // Split out upright text runs (\text/\mathrm/\operatorname/…) from math runs;
  // words read upright, single-letter variables stay italic for a real math feel.
  const parts: ReactNode[] = [];
  const re = /\\(?:text|textrm|textbf|textit|mathrm|mathbf|mathit|operatorname|mbox)\{([^{}]*)\}/g;
  let last = 0;
  let m: RegExpExecArray | null;
  let k = 0;
  while ((m = re.exec(s)) !== null) {
    if (m.index > last) {
      parts.push(
        <em key={`${keyBase}-m-${k++}`} className="italic">
          {tokenizeScripts(s.slice(last, m.index), keyBase * 31 + k)}
        </em>
      );
    }
    parts.push(
      <span key={`${keyBase}-t-${k++}`} className="not-italic">
        {tokenizeScripts(m[1], keyBase * 37 + k)}
      </span>
    );
    last = m.index + m[0].length;
  }
  if (last < s.length) {
    parts.push(
      <em key={`${keyBase}-m-${k++}`} className="italic">
        {tokenizeScripts(s.slice(last), keyBase * 31 + k)}
      </em>
    );
  }
  return (
    <span key={keyBase} className="font-serif tracking-tight text-white/90">
      {parts}
    </span>
  );
}

// ---- inline (math / bold / italic / code / links) ----
type InlineRule = {
  re: RegExp;
  render: (m: RegExpMatchArray, key: number) => ReactNode;
};

const INLINE: InlineRule[] = [
  {
    re: /\$([^$\n]+)\$/,
    render: (m, key) =>
      looksLikeMath(m[1]) ? renderMath(m[1], key) : <Fragment key={key}>{m[0]}</Fragment>,
  },
  {
    re: /`([^`]+)`/,
    render: (m, key) => (
      <code key={key} className="rounded-md bg-white/[0.08] px-1.5 py-0.5 font-mono text-[0.85em] text-[#f5b95f]">
        {m[1]}
      </code>
    ),
  },
  {
    re: /\[([^\]]+)\]\(([^)\s]+)\)/,
    render: (m, key) =>
      isSafeHref(m[2]) ? (
        <a
          key={key}
          href={m[2]}
          target="_blank"
          rel="noopener noreferrer"
          className="font-medium text-[#f5b95f] underline decoration-[#f5b95f]/40 underline-offset-2 hover:decoration-[#f5b95f]"
        >
          {m[1]}
        </a>
      ) : (
        <span key={key}>{m[1]}</span>
      ),
  },
  {
    re: /\*\*([^*]+)\*\*/,
    render: (m, key) => <strong key={key} className="font-semibold text-white">{inline(m[1], key * 97)}</strong>,
  },
  {
    re: /(?<![*\w])\*([^*\n]+)\*(?!\w)/,
    render: (m, key) => <em key={key} className="italic">{inline(m[1], key * 89)}</em>,
  },
];

function inline(text: string, keyBase = 0): ReactNode[] {
  let best: { rule: InlineRule; m: RegExpMatchArray } | null = null;
  for (const rule of INLINE) {
    const m = text.match(rule.re);
    if (m && m.index !== undefined && (!best || m.index < best.m.index!)) best = { rule, m };
  }
  if (!best) return [text];
  const { m, rule } = best;
  const start = m.index!;
  return [
    text.slice(0, start),
    rule.render(m, keyBase + start + 1),
    ...inline(text.slice(start + m[0].length), keyBase + start + 2),
  ];
}

// ---- block level ----
export default function Markdown({
  children,
  className,
  vizAccent,
  strictViz = false,
}: {
  children: string;
  className?: string;
  /** Accent colour passed through to `viz:*` diagrams (defaults per-primitive). */
  vizAccent?: string;
  /** Set by hand-authored story content — a malformed `viz:*` payload throws
   * (fails the SSG build loudly) instead of rendering an inline error card.
   * Never set for user-authored content (e.g. personal notes). */
  strictViz?: boolean;
}) {
  const lines = children.replace(/\r\n/g, "\n").split("\n");
  const blocks: ReactNode[] = [];
  let i = 0;
  let key = 0;

  while (i < lines.length) {
    const line = lines[i];

    // fenced code (and viz:* diagram blocks — same fence, an info-string tag)
    const fence = line.trim().match(/^```(\S*)/);
    if (fence) {
      const lang = fence[1] ?? "";
      const buf: string[] = [];
      i++;
      while (i < lines.length && !/^```/.test(lines[i].trim())) buf.push(lines[i++]);
      i++; // closing fence
      const content = buf.join("\n");
      if (lang.startsWith("viz:")) {
        blocks.push(<VizBlock key={key++} kind={lang.slice(4)} raw={content} accent={vizAccent} strict={strictViz} />);
      } else {
        blocks.push(
          <pre key={key++} className="my-3 overflow-x-auto rounded-xl bg-black/30 p-4 font-mono text-[0.85em] leading-relaxed text-white/85">
            <code>{content}</code>
          </pre>
        );
      }
      continue;
    }

    // blank
    if (line.trim() === "") { i++; continue; }

    // horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})$/.test(line.trim())) {
      blocks.push(<hr key={key++} className="my-5 border-white/10" />);
      i++;
      continue;
    }

    // headings
    const h = line.match(/^(#{1,6})\s+(.*)$/);
    if (h) {
      const level = h[1].length;
      const sizes = ["text-2xl", "text-xl", "text-lg", "text-base", "text-sm", "text-sm"];
      blocks.push(
        <p key={key++} className={`display mt-4 mb-2 font-bold text-white ${sizes[level - 1]}`}>
          {inline(h[2])}
        </p>
      );
      i++;
      continue;
    }

    // blockquote
    if (/^>\s?/.test(line)) {
      const buf: string[] = [];
      while (i < lines.length && /^>\s?/.test(lines[i])) buf.push(lines[i++].replace(/^>\s?/, ""));
      blocks.push(
        <blockquote key={key++} className="my-3 border-l-2 border-[#f5b95f]/50 pl-4 italic text-white/70">
          {inline(buf.join(" "))}
        </blockquote>
      );
      continue;
    }

    // ordered list
    if (/^\s*\d+\.\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) items.push(lines[i++].replace(/^\s*\d+\.\s+/, ""));
      blocks.push(
        <ol key={key++} className="my-3 ml-1 list-decimal space-y-1.5 pl-5 marker:text-faint">
          {items.map((it, j) => <li key={j} className="pl-1">{inline(it)}</li>)}
        </ol>
      );
      continue;
    }

    // unordered list
    if (/^\s*[-*+]\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^\s*[-*+]\s+/.test(lines[i])) items.push(lines[i++].replace(/^\s*[-*+]\s+/, ""));
      blocks.push(
        <ul key={key++} className="my-3 space-y-1.5">
          {items.map((it, j) => (
            <li key={j} className="flex gap-2.5">
              <span className="mt-[0.55em] h-1 w-1 shrink-0 rounded-full bg-[#f5b95f]/70" />
              <span className="flex-1">{inline(it)}</span>
            </li>
          ))}
        </ul>
      );
      continue;
    }

    // paragraph — gather consecutive non-blank, non-block lines
    const buf: string[] = [];
    while (
      i < lines.length &&
      lines[i].trim() !== "" &&
      !/^```/.test(lines[i].trim()) &&
      !/^(#{1,6})\s+/.test(lines[i]) &&
      !/^>\s?/.test(lines[i]) &&
      !/^\s*\d+\.\s+/.test(lines[i]) &&
      !/^\s*[-*+]\s+/.test(lines[i]) &&
      !/^(-{3,}|\*{3,}|_{3,})$/.test(lines[i].trim())
    ) {
      buf.push(lines[i++]);
    }
    blocks.push(
      <p key={key++} className="my-2.5 leading-relaxed">
        {buf.map((b, j) => (
          <Fragment key={j}>
            {j > 0 && <br />}
            {inline(b)}
          </Fragment>
        ))}
      </p>
    );
  }

  return <div className={className}>{blocks}</div>;
}

"use client";

import { useEffect, useRef } from "react";

interface ThanosSnapCanvasProps {
  isActive: boolean;
  clickPos: { x: number; y: number } | null;
  mode: "to-paper" | "to-dark";
  onThemeFlip: () => void;
  onComplete: () => void;
}

// ---- timing (ms, wall-clock via performance.now) ----
const DURATION_MS = 1700; // total duration
const REVEAL_MS = 1050; // time for reveal circle to reach full radius
const FLIP_GUARD_MS = 80; // hold before hole starts
const PARTICLE_LIFE_MS = 600;
const SPAWN_STOP_RT = 0.9; // stop spawning once reveal is 90% done

// ---- reveal geometry ----
const FEATHER_PX = 90; // soft width of dissolving edge

// ---- particles ----
const SPAWN_PER_FRAME = 14;
const PARTICLE_MAX = 2200;
const SIZE_MIN = 0.8;
const SIZE_MAX = 2.6; // radius px
const SPEED_MIN = 0.02;
const SPEED_MAX = 0.09; // outward drift px/ms
const UP_DRIFT = 0.02; // upward bias px/ms
const SWAY_AMP = 0.5; // horizontal sine sway px
const ACCENT_RATIO = 0.4; // ~40% accent, ~60% neutral

// ---- rendering ----
const DPR_CAP = 2;
const SPRITE_PX = 24;

const easeInOutCubic = (x: number) =>
  x < 0.5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2;

// ---- color tokens ----
const DARK_BG = "#0b0a0e";
const PAPER_BG = "#eee8dd";

const DARK_NEUTRAL = ["#1a1721", "#2c2834", "#6d6875", "#a5a1ab"];
const DARK_ACCENT = ["#ff7a5c", "#f5b95f", "#43d6b5"];
const PAPER_NEUTRAL = ["#e4ddd0", "#d1c9b9", "#8a8174", "#3a342d"];
const PAPER_ACCENT = ["#cf4225", "#aa6f1e", "#187369"];

const SHIMMER_TO_PAPER = "rgba(245,185,95,0.55)";
const SHIMMER_TO_DARK = "rgba(170,111,30,0.5)";

function makeSprite(color: string): HTMLCanvasElement {
  const s = document.createElement("canvas");
  s.width = s.height = SPRITE_PX;
  const sctx = s.getContext("2d")!;
  const r = SPRITE_PX / 2;
  const grad = sctx.createRadialGradient(r, r, 0, r, r, r);
  grad.addColorStop(0, color);
  grad.addColorStop(0.35, color);
  grad.addColorStop(1, "transparent");
  sctx.fillStyle = grad;
  sctx.beginPath();
  sctx.arc(r, r, r, 0, Math.PI * 2);
  sctx.fill();
  return s;
}

interface InkParticle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  born: number;
  sprite: HTMLCanvasElement;
  seed: number;
}

export default function ThanosSnapCanvas({
  isActive,
  clickPos,
  mode,
  onThemeFlip,
  onComplete,
}: ThanosSnapCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const flippedRef = useRef(false);

  useEffect(() => {
    if (!isActive) {
      flippedRef.current = false;
      return;
    }

    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const W = window.innerWidth;
    const H = window.innerHeight;
    const dpr = Math.min(window.devicePixelRatio || 1, DPR_CAP);

    canvas.width = Math.floor(W * dpr);
    canvas.height = Math.floor(H * dpr);
    canvas.style.width = `${W}px`;
    canvas.style.height = `${H}px`;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

    const originX = clickPos ? clickPos.x : W / 2;
    const originY = clickPos ? clickPos.y : H / 2;
    const maxRadius =
      Math.hypot(Math.max(originX, W - originX), Math.max(originY, H - originY)) +
      FEATHER_PX;
    const toPaper = mode === "to-paper";
    const sheetColor = toPaper ? DARK_BG : PAPER_BG;

    const palette = toPaper
      ? { neutral: DARK_NEUTRAL, accent: DARK_ACCENT }
      : { neutral: PAPER_NEUTRAL, accent: PAPER_ACCENT };

    const spriteCache = new Map<string, HTMLCanvasElement>();
    const spriteFor = (c: string) => {
      let sp = spriteCache.get(c);
      if (!sp) {
        sp = makeSprite(c);
        spriteCache.set(c, sp);
      }
      return sp;
    };

    const inks: InkParticle[] = [];
    const start = performance.now();
    let lastTime = start;
    let animId: number;

    const render = (now: number) => {
      const t = now - start;
      const dt = now - lastTime;
      lastTime = now;

      // Flip DOM theme on frame 1 hidden underneath opaque sheet
      if (!flippedRef.current) {
        flippedRef.current = true;
        onThemeFlip();
      }

      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.clearRect(0, 0, W, H);

      const rt = Math.min(1, Math.max(0, (t - FLIP_GUARD_MS) / REVEAL_MS));
      const radius = easeInOutCubic(rt) * maxRadius;

      // Layer 1: Opaque old-theme sheet over everything
      ctx.globalCompositeOperation = "source-over";
      ctx.globalAlpha = 1;
      ctx.fillStyle = sheetColor;
      ctx.fillRect(0, 0, W, H);

      // Layer 2: Erase soft-edged hole -> new theme shows through
      if (radius > 0) {
        ctx.globalCompositeOperation = "destination-out";
        const inner = Math.max(0, radius - FEATHER_PX);
        const g = ctx.createRadialGradient(originX, originY, inner, originX, originY, radius);
        g.addColorStop(0, "rgba(0,0,0,1)");
        g.addColorStop(1, "rgba(0,0,0,0)");
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(originX, originY, radius, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalCompositeOperation = "source-over";
      }

      // Layer 3a: Spawn & render glowing ink particles along the crumbling edge
      if (rt > 0 && rt < SPAWN_STOP_RT && inks.length < PARTICLE_MAX) {
        for (let k = 0; k < SPAWN_PER_FRAME; k++) {
          const a = Math.random() * Math.PI * 2;
          const rr = radius - Math.random() * FEATHER_PX;
          const speed = SPEED_MIN + Math.random() * (SPEED_MAX - SPEED_MIN);
          const pool = Math.random() < ACCENT_RATIO ? palette.accent : palette.neutral;
          const color = pool[(Math.random() * pool.length) | 0];
          inks.push({
            x: originX + Math.cos(a) * rr,
            y: originY + Math.sin(a) * rr,
            vx: Math.cos(a) * speed,
            vy: Math.sin(a) * speed - UP_DRIFT,
            size: SIZE_MIN + Math.random() * (SIZE_MAX - SIZE_MIN),
            born: t,
            sprite: spriteFor(color),
            seed: Math.random() * 100,
          });
        }
      }

      let write = 0;
      for (let i = 0; i < inks.length; i++) {
        const p = inks[i];
        const age = t - p.born;
        if (age >= PARTICLE_LIFE_MS) continue;

        p.x += p.vx * dt + Math.sin(t * 0.004 + p.seed) * SWAY_AMP * (dt / 16.7);
        p.y += p.vy * dt;

        const lifeT = age / PARTICLE_LIFE_MS;
        ctx.globalAlpha = 1 - lifeT * lifeT;
        const sz = p.size * (1 - 0.35 * lifeT) * 3;
        ctx.drawImage(p.sprite, p.x - sz, p.y - sz, sz * 2, sz * 2);
        inks[write++] = p;
      }
      inks.length = write;
      ctx.globalAlpha = 1;

      // Layer 3b: Reveal edge shimmer ring
      if (rt > 0 && rt < 1) {
        ctx.save();
        ctx.globalCompositeOperation = "source-over";
        ctx.strokeStyle = toPaper ? SHIMMER_TO_PAPER : SHIMMER_TO_DARK;
        ctx.lineWidth = 2;
        ctx.shadowColor = ctx.strokeStyle as string;
        ctx.shadowBlur = 14;
        ctx.globalAlpha = 0.7 * (1 - rt);
        ctx.beginPath();
        ctx.arc(originX, originY, radius, 0, Math.PI * 2);
        ctx.stroke();
        ctx.restore();
      }

      // Check completion
      if (t >= DURATION_MS) {
        cancelAnimationFrame(animId);
        onComplete();
        return;
      }

      animId = requestAnimationFrame(render);
    };

    animId = requestAnimationFrame(render);

    return () => {
      cancelAnimationFrame(animId);
    };
  }, [isActive, clickPos, mode, onThemeFlip, onComplete]);

  if (!isActive) return null;

  return (
    <canvas
      ref={canvasRef}
      className="pointer-events-none fixed inset-0 z-[9999] h-full w-full"
      style={{ isolation: "isolate" }}
    />
  );
}

"use client";

import { useEffect, useRef, useState } from "react";

/**
 * Paper-fold theme transition.
 *
 * The old design was a single soft-edged reveal circle sweeping the screen
 * (one big "wave"). This replaces it with a grid of small paper tiles that each
 * fold away in 3D — an accordion of little sheets radiating out from the click,
 * revealing the new theme underneath. Much more like "many small papers folding"
 * than a wave running across the screen.
 *
 * Same props/contract as before so `ReadingThemeContext` is unchanged: the DOM
 * theme is flipped once (hidden beneath the still-covering tiles) and
 * `onComplete` fires after the last tile has folded.
 */
interface ThanosSnapCanvasProps {
  isActive: boolean;
  clickPos: { x: number; y: number } | null;
  mode: "to-paper" | "to-dark";
  onThemeFlip: () => void;
  onComplete: () => void;
}

// ---- color tokens ----
const DARK_BG = "#0b0a0e";
const PAPER_BG = "#eee8dd";

// ---- paper-fold transition ----
const TILE_PX = 74; // target tile size — keeps ~300 tiles on a laptop screen
const FOLD_MS = 560; // per-tile fold duration
const MAX_STAGGER_MS = 620; // radial spread from the click origin
const JITTER_MS = 140; // organic per-tile randomness

interface Tile {
  x: number;
  y: number;
  w: number;
  h: number;
  delay: number;
  dir: 1 | -1; // fold up or down (checkerboard so it doesn't read as one wave)
  rot: number; // small z-tilt for a hand-folded feel
}

export default function ThanosSnapCanvas({
  isActive,
  clickPos,
  mode,
  onThemeFlip,
  onComplete,
}: ThanosSnapCanvasProps) {
  const [tiles, setTiles] = useState<Tile[] | null>(null);
  const [folding, setFolding] = useState(false);
  const [origin, setOrigin] = useState({ x: 0, y: 0 });

  // Keep the latest callbacks without re-running the setup effect (the theme
  // flip changes their identity mid-animation, which must NOT restart it).
  const flipRef = useRef(onThemeFlip);
  const doneRef = useRef(onComplete);
  flipRef.current = onThemeFlip;
  doneRef.current = onComplete;

  useEffect(() => {
    if (!isActive) {
      setTiles(null);
      setFolding(false);
      return;
    }

    const W = window.innerWidth;
    const H = window.innerHeight;
    const cols = Math.max(1, Math.round(W / TILE_PX));
    const rows = Math.max(1, Math.round(H / TILE_PX));
    const tw = W / cols;
    const th = H / rows;
    const ox = clickPos?.x ?? W / 2;
    const oy = clickPos?.y ?? H / 2;
    const maxD = Math.hypot(Math.max(ox, W - ox), Math.max(oy, H - oy)) || 1;

    const arr: Tile[] = [];
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const cx = c * tw + tw / 2;
        const cy = r * th + th / 2;
        const d = Math.hypot(cx - ox, cy - oy) / maxD;
        arr.push({
          x: c * tw,
          y: r * th,
          w: tw + 1, // +1 hides sub-pixel seams while still covering
          h: th + 1,
          delay: d * MAX_STAGGER_MS + Math.random() * JITTER_MS,
          dir: (r + c) % 2 === 0 ? 1 : -1,
          rot: (Math.random() - 0.5) * 7,
        });
      }
    }

    setOrigin({ x: ox, y: oy });
    setTiles(arr);
    setFolding(false);

    // Two rAFs so the covered (un-folded) state paints before we flip the DOM
    // theme underneath and kick off the CSS fold transition.
    let raf2 = 0;
    const raf1 = requestAnimationFrame(() => {
      raf2 = requestAnimationFrame(() => {
        flipRef.current();
        setFolding(true);
      });
    });

    const maxDelay = arr.reduce((m, t) => Math.max(m, t.delay), 0);
    const timer = window.setTimeout(() => doneRef.current(), maxDelay + FOLD_MS + 140);

    return () => {
      cancelAnimationFrame(raf1);
      cancelAnimationFrame(raf2);
      clearTimeout(timer);
    };
  }, [isActive, clickPos, mode]);

  if (!isActive || !tiles) return null;

  const toPaper = mode === "to-paper";
  // Tiles show the OLD theme's page colour while they still cover the screen.
  const sheet = toPaper ? DARK_BG : PAPER_BG;
  const sheenTop = toPaper ? "rgba(255,255,255,0.05)" : "rgba(255,255,255,0.6)";
  const sheenBot = toPaper ? "rgba(0,0,0,0.4)" : "rgba(120,102,74,0.22)";
  const edge = toPaper ? "rgba(255,255,255,0.05)" : "rgba(120,102,74,0.16)";

  return (
    <div
      className="pointer-events-none fixed inset-0 z-[9999] overflow-hidden"
      style={{
        perspective: "1200px",
        perspectiveOrigin: `${origin.x}px ${origin.y}px`,
        isolation: "isolate",
      }}
    >
      {tiles.map((t, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            left: t.x,
            top: t.y,
            width: t.w,
            height: t.h,
            backgroundColor: sheet,
            backgroundImage: `linear-gradient(155deg, ${sheenTop}, transparent 55%, ${sheenBot})`,
            boxShadow: `inset 0 0 0 0.5px ${edge}`,
            transformOrigin: t.dir === 1 ? "center top" : "center bottom",
            transform: folding
              ? `rotateX(${t.dir * -92}deg) rotateZ(${t.rot}deg) translateZ(0)`
              : "rotateX(0deg)",
            opacity: folding ? 0 : 1,
            transition: `transform ${FOLD_MS}ms cubic-bezier(0.62,0.02,0.34,1) ${t.delay}ms, opacity ${FOLD_MS}ms ease ${t.delay + FOLD_MS * 0.4}ms`,
            backfaceVisibility: "hidden",
            willChange: "transform, opacity",
          }}
        />
      ))}
    </div>
  );
}

"use client";

/**
 * Client data layer. Every page talks to this module; it switches between
 * demo data (no Supabase configured) and the real Supabase + API backend.
 */
import { createClient } from "./supabase/client";
import {
  isDemo,
  demoTopics,
  demoLinks,
  demoEntries,
  demoFacts,
  demoProfile,
  demoReviews,
  demoPlan,
  demoQuestionBank,
  demoGrade,
  demoTopicSource,
} from "./demo";
import { localDayKey, localDayStartIso, localDayEndIso, tzOffsetMinutes } from "./dates";
import type {
  DailyFact,
  DailyPlan,
  Entry,
  Profile,
  QuizSession,
  ReportCard,
  ReportItem,
  Review,
  SessionQuestion,
  Topic,
  TopicLink,
  TopicQuestion,
  TopicSource,
} from "./types";

export { isDemo };
export * from "./stories";

/** Demo quiz session: the client-safe questions plus the hidden answer key. */
interface DemoSession {
  id: string;
  questions: SessionQuestion[];
  key: Map<
    number,
    { correct_index: number | null; correct_indices: number[] | null; model_answer: string }
  >;
  answers: Map<number, { answer?: string; selectedIndex?: number; selectedIndices?: number[] }>;
}

// Demo-mode mutable state. Persisted to localStorage so guest progress
// survives reloads and hard navigations (done flags reset on a new day,
// like the real backend; reviews/reports/streak carry over).
const DEMO_STATE_KEY = "knovis.demo.v1";

const demoState = {
  profile: { ...demoProfile },
  plan: JSON.parse(JSON.stringify(demoPlan)) as DailyPlan,
  done: new Set<string>(),
  reviews: [...demoReviews] as Review[],
  session: null as DemoSession | null,
  reports: [] as ReportCard[], // graded reports (feeds day report cards)
};

function saveDemoState(): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      DEMO_STATE_KEY,
      JSON.stringify({
        day: localDayKey(),
        profile: demoState.profile,
        completed: demoState.plan.completed,
        done: Array.from(demoState.done),
        reviews: demoState.reviews,
        reports: demoState.reports,
      })
    );
  } catch { /* storage full/blocked — demo stays in-memory */ }
}

function loadDemoState(): void {
  if (typeof window === "undefined") return;
  try {
    const raw = window.localStorage.getItem(DEMO_STATE_KEY);
    if (!raw) return;
    const saved = JSON.parse(raw) as {
      day?: string;
      profile?: Profile;
      completed?: boolean;
      done?: string[];
      reviews?: Review[];
      reports?: ReportCard[];
    };
    if (saved.profile) demoState.profile = { ...demoState.profile, ...saved.profile };
    if (Array.isArray(saved.reviews) && saved.reviews.length) demoState.reviews = saved.reviews;
    if (Array.isArray(saved.reports)) demoState.reports = saved.reports;
    // Done flags and day-completion only carry within the same local day.
    if (saved.day === localDayKey()) {
      demoState.done = new Set(saved.done ?? []);
      demoState.plan.completed = !!saved.completed;
    }
  } catch { /* corrupted blob — start fresh */ }
}

if (isDemo) loadDemoState();

/** Thrown by api() — carries the HTTP status so callers can branch on it (e.g. 429 rate limits) without parsing the message text. */
export class ApiError extends Error {
  status: number;
  /** ISO instant of the client's next local midnight, when a 429 daily-limit error includes one. */
  resetAt?: string;
  constructor(message: string, status: number, resetAt?: string) {
    super(message);
    this.status = status;
    this.resetAt = resetAt;
  }
}

async function api<T>(path: string, body?: unknown): Promise<T> {
  const res = await fetch(path, {
    method: body === undefined ? "GET" : "POST",
    headers: { "Content-Type": "application/json" },
    body: body === undefined ? undefined : JSON.stringify(body),
  });
  if (!res.ok) {
    // `??` only falls back on null/undefined — over HTTP/2, res.statusText is
    // ALWAYS "" (no reason phrases), so a non-JSON error body (platform crash
    // or timeout) used to produce `new Error("")`, which the UI then rendered
    // as nothing (`{error && ...}` is falsy for ""). Include res.status so the
    // fallback is never blank.
    const err = await res.json().catch(() => ({}));
    throw new ApiError(err.error || `Request failed (${res.status})`, res.status, err.resetAt);
  }
  return res.json();
}

export async function getProfile(): Promise<Profile> {
  if (isDemo) return demoState.profile;
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) throw new Error("Not signed in");
  const { data, error } = await supabase
    .from("profiles")
    .select("*")
    .eq("id", user.id)
    .maybeSingle();
  if (error) throw error;
  if (data) return data as Profile;
  // No profile row — e.g. the account predates the handle_new_user trigger, or
  // the trigger was never installed. Self-heal by creating the row now so the
  // profile page (and dashboard greeting) never hang on a missing row.
  const displayName =
    (user.user_metadata?.name as string | undefined) ?? user.email?.split("@")[0] ?? null;
  const { data: created, error: insertErr } = await supabase
    .from("profiles")
    .upsert({ id: user.id, display_name: displayName }, { onConflict: "id" })
    .select()
    .single();
  if (insertErr) throw insertErr;
  return created as Profile;
}

export async function updateProfile(fields: { display_name: string }): Promise<Profile> {
  if (isDemo) {
    demoState.profile = { ...demoState.profile, ...fields };
    saveDemoState();
    return demoState.profile;
  }
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  const { data, error } = await supabase
    .from("profiles")
    .update(fields)
    .eq("id", user!.id)
    .select()
    .single();
  if (error) throw error;
  return data as Profile;
}

export async function getUserEmail(): Promise<string | null> {
  if (isDemo) return null;
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  return user?.email ?? null;
}

export async function getTopics(): Promise<Topic[]> {
  if (isDemo) return demoTopics;
  const supabase = createClient();
  const { data } = await supabase.from("topics").select("*").order("created_at", { ascending: false });
  return (data ?? []) as Topic[];
}

export async function getTopic(id: string): Promise<Topic | null> {
  if (isDemo) return demoTopics.find((t) => t.id === id) ?? null;
  const supabase = createClient();
  const { data } = await supabase.from("topics").select("*").eq("id", id).single();
  return data as Topic | null;
}

/**
 * Where a topic came from, for its blog page: the source_url of the entry it
 * was extracted from (a link), or `text` when it was pasted in. Null if unknown.
 */
export async function getTopicSource(topicId: string): Promise<TopicSource> {
  if (isDemo) {
    return demoTopicSource[topicId] ?? { kind: "text" };
  }
  const supabase = createClient();
  const { data } = await supabase
    .from("entry_topics")
    .select("entries(source_url, created_at)")
    .eq("topic_id", topicId);
  const rows = (data ?? []) as unknown as Array<{
    entries: { source_url: string | null; created_at: string } | null;
  }>;
  const entries = rows
    .map((r) => r.entries)
    .filter((e): e is { source_url: string | null; created_at: string } => !!e)
    .sort((a, b) => b.created_at.localeCompare(a.created_at));
  if (entries.length === 0) return null;
  const withUrl = entries.find((e) => e.source_url);
  if (withUrl?.source_url) return { kind: "url", url: withUrl.source_url };
  return { kind: "text" };
}

export async function getLinks(): Promise<TopicLink[]> {
  if (isDemo) return demoLinks;
  const supabase = createClient();
  const { data } = await supabase.from("topic_links").select("*");
  return (data ?? []) as TopicLink[];
}

export async function getEntries(): Promise<Entry[]> {
  if (isDemo) return demoEntries;
  const supabase = createClient();
  const { data } = await supabase
    .from("entries")
    .select("id, title, summary, created_at")
    .order("created_at", { ascending: false })
    .limit(20);
  return (data ?? []).map((e) => ({ ...e, raw_text: "" })) as Entry[];
}

/** All bank questions for one topic, WITH answers — for the topic's blog page. */
export async function getTopicQuestions(topicId: string): Promise<TopicQuestion[]> {
  if (isDemo) {
    return demoQuestionBank
      .filter((q) => q.topic_id === topicId)
      .map((q, i) => ({
        id: `demo-q-${topicId}-${i}`,
        topic_id: q.topic_id,
        kind: q.kind,
        prompt: q.prompt,
        options: q.options,
        correct_index: q.correct_index,
        correct_indices: q.correct_indices ?? null,
        model_answer: q.model_answer,
        difficulty: "basic",
      }));
  }
  const supabase = createClient();
  // select * so databases without the newer correct_indices column still work.
  const { data } = await supabase
    .from("questions")
    .select("*")
    .eq("topic_id", topicId)
    .order("created_at", { ascending: true });
  return ((data ?? []) as Record<string, unknown>[]).map((q) => ({
    id: q.id as string,
    topic_id: q.topic_id as string,
    kind: q.kind as TopicQuestion["kind"],
    prompt: q.prompt as string,
    options: (q.options as string[] | null) ?? null,
    correct_index: (q.correct_index as number | null) ?? null,
    correct_indices: (q.correct_indices as number[] | null) ?? null,
    model_answer: q.model_answer as string,
    difficulty: (q.difficulty as string) ?? "basic",
  }));
}

export async function getReviews(sinceDays = 120): Promise<Review[]> {
  if (isDemo) return demoState.reviews;
  const supabase = createClient();
  const since = new Date();
  since.setDate(since.getDate() - sinceDays);
  const { data } = await supabase
    .from("reviews")
    .select("id, topic_id, mode, score, question, answer, feedback, created_at")
    .gte("created_at", since.toISOString())
    .order("created_at", { ascending: false });
  return (data ?? []) as Review[];
}

export async function getPlan(): Promise<DailyPlan> {
  if (isDemo) {
    return {
      ...demoState.plan,
      items: demoState.plan.items.map((it) => ({
        ...it,
        done: demoState.done.has(it.topic_id),
      })),
    };
  }
  return api<DailyPlan>(`/api/plan?tz=${tzOffsetMinutes()}`);
}

export interface IngestResult {
  entryTitle: string;
  topicNames: string[];
  sourceUrl?: string | null;
  /** True when this exact content was already ingested — the existing entry was reused, nothing new was created. */
  duplicate?: boolean;
  message?: string;
}

export async function ingestText(text: string): Promise<IngestResult> {
  if (isDemo) {
    await new Promise((r) => setTimeout(r, 1800));
    return {
      entryTitle: "Demo: knowledge extracted",
      topicNames: ["(Demo mode — add Supabase + Gemini keys to save real entries)"],
    };
  }
  return api("/api/ingest", { text, tz: tzOffsetMinutes() });
}

export async function ingestLink(url: string): Promise<IngestResult> {
  if (isDemo) {
    await new Promise((r) => setTimeout(r, 2200));
    let host = "the article";
    try {
      host = new URL(url).hostname.replace(/^www\./, "");
    } catch { /* keep fallback */ }
    return {
      entryTitle: `Demo: article from ${host}`,
      topicNames: ["(Demo mode — add Supabase + Gemini keys to fetch and save real articles)"],
      sourceUrl: url,
    };
  }
  return api("/api/ingest", { url, tz: tzOffsetMinutes() });
}

/**
 * Start a review session: questions come from the pre-generated bank, so this
 * costs zero AI calls. The client never receives the correct answers.
 */
export async function startQuiz(topicIds: string[]): Promise<QuizSession> {
  if (isDemo) {
    await new Promise((r) => setTimeout(r, 500));
    const kinds = ["open", "mcq", "truefalse", "quickfire", "multi"] as const;
    const questions: SessionQuestion[] = [];
    const key = new Map<
      number,
      { correct_index: number | null; correct_indices: number[] | null; model_answer: string }
    >();
    topicIds.forEach((topicId, i) => {
      const topic = demoTopics.find((t) => t.id === topicId);
      if (!topic) return;
      const pool = demoQuestionBank.filter((q) => q.topic_id === topicId);
      const bank =
        pool.find((q) => q.kind === kinds[i % kinds.length]) ?? pool[0] ?? null;
      const index = questions.length;
      if (bank) {
        questions.push({
          index,
          topic_id: topic.id,
          topic_name: topic.name,
          category: topic.category,
          kind: bank.kind,
          prompt: bank.prompt,
          options: bank.options,
        });
        key.set(index, {
          correct_index: bank.correct_index,
          correct_indices: bank.correct_indices ?? null,
          model_answer: bank.model_answer,
        });
      } else {
        questions.push({
          index,
          topic_id: topic.id,
          topic_name: topic.name,
          category: topic.category,
          kind: "open",
          prompt:
            topic.category === "Computer Science"
              ? `For the algorithm "${topic.name}", explain the core pattern or recurrence relation used to solve it, and state the time and space complexity of the optimal approach.`
              : `From memory, explain "${topic.name}" — the core idea and why it matters.`,
          options: null,
        });
        key.set(index, {
          correct_index: null,
          correct_indices: null,
          model_answer: topic.key_points.join(" "),
        });
      }
    });
    demoState.session = { id: `demo-${Date.now()}`, questions, key, answers: new Map() };
    return { id: demoState.session.id, questions };
  }
  return api("/api/quiz", { action: "start", topicIds });
}

/** Save one answer the moment it's submitted — persisted in the DB, no AI. */
export async function saveQuizAnswer(args: {
  sessionId: string;
  questionIndex: number;
  answer?: string;
  selectedIndex?: number;
  selectedIndices?: number[];
}): Promise<void> {
  if (isDemo) {
    demoState.session?.answers.set(args.questionIndex, {
      answer: args.answer,
      selectedIndex: args.selectedIndex,
      selectedIndices: args.selectedIndices,
    });
    return;
  }
  await api("/api/quiz", { action: "answer", ...args });
}

/**
 * Finish the session: the ONE AI call grades everything at once and returns
 * the report card (demo mode grades locally).
 */
export async function finishQuiz(sessionId: string): Promise<ReportCard> {
  if (isDemo) {
    await new Promise((r) => setTimeout(r, 1200));
    const s = demoState.session;
    if (!s || s.id !== sessionId) throw new Error("Session not found");
    const items: ReportItem[] = [];
    for (const q of s.questions) {
      const a = s.answers.get(q.index);
      if (!a) continue; // never presented this session
      const key = s.key.get(q.index)!;
      const topic = demoTopics.find((t) => t.id === q.topic_id)!;
      const item: ReportItem = {
        index: q.index,
        topic_id: q.topic_id,
        topic_name: q.topic_name,
        kind: q.kind,
        prompt: q.prompt,
        answer: null,
        skipped: false,
        correct: null,
        score: 0,
        feedback: "",
        correct_answer: key.model_answer,
        options: q.options,
        selected_index: null,
        correct_index: q.kind === "mcq" || q.kind === "truefalse" ? key.correct_index : null,
        selected_indices: null,
        correct_indices: q.kind === "multi" ? key.correct_indices : null,
      };
      if (q.kind === "mcq" || q.kind === "truefalse") {
        const sel = typeof a.selectedIndex === "number" ? a.selectedIndex : null;
        item.selected_index = sel;
        item.answer = sel !== null ? q.options?.[sel] ?? null : null;
        if (sel === null) {
          item.skipped = true;
          item.feedback = "You skipped this one — no harm done, it'll come back around.";
        } else {
          item.correct = sel === key.correct_index;
          item.score = item.correct ? 5 : 1;
          item.feedback = item.correct
            ? "Correct — you picked the right option."
            : `Not quite — the right answer was "${q.options?.[key.correct_index ?? 0] ?? ""}".`;
        }
        if (key.correct_index !== null && q.options) {
          item.correct_answer = q.options[key.correct_index] ?? key.model_answer;
        }
      } else if (q.kind === "multi") {
        const sel = a.selectedIndices?.filter((n) => typeof n === "number") ?? null;
        const answerKey = key.correct_indices ?? [];
        item.selected_indices = sel;
        item.answer =
          sel && q.options ? sel.map((i) => q.options![i]).filter(Boolean).join(" · ") || null : null;
        item.correct_answer =
          answerKey.length && q.options
            ? answerKey.map((i) => q.options![i]).filter(Boolean).join(" · ")
            : key.model_answer;
        if (!sel || sel.length === 0) {
          item.skipped = true;
          item.feedback = "You skipped this one — no harm done, it'll come back around.";
        } else {
          const hits = sel.filter((i) => answerKey.includes(i)).length;
          const wrong = sel.length - hits;
          item.correct = hits === answerKey.length && wrong === 0;
          item.score = item.correct
            ? 5
            : Math.max(0, Math.min(4, Math.round((5 * Math.max(0, hits - wrong)) / Math.max(1, answerKey.length))));
          item.feedback = item.correct
            ? "Correct — you picked every right option."
            : hits > 0
              ? `Partly right — you found ${hits} of ${answerKey.length} correct option${answerKey.length === 1 ? "" : "s"}${wrong ? ` but also picked ${wrong} wrong one${wrong === 1 ? "" : "s"}` : ""}.`
              : "Not quite — none of your picks were correct this time.";
        }
      } else {
        const typed = (a.answer ?? "").trim();
        item.answer = typed || null;
        if (!typed) {
          item.skipped = true;
          item.feedback = "You skipped this one — no harm done, it'll come back around.";
        } else {
          const g = demoGrade(typed, topic.key_points);
          item.score = g.score;
          item.feedback = g.feedback;
        }
      }
      items.push(item);
      demoState.done.add(q.topic_id);
    }
    const attempted = items.filter((i) => !i.skipped);
    const scorePct = attempted.length
      ? Math.round((attempted.reduce((sum, i) => sum + i.score, 0) / (attempted.length * 5)) * 100)
      : 0;
    const strengths = attempted.filter((i) => i.score >= 4).map((i) => i.topic_name).slice(0, 3);
    const focus = attempted.filter((i) => i.score <= 2).map((i) => i.topic_name).slice(0, 3);

    // Also add to demoState.reviews so it shows up in calendar and review detail!
    for (const q of s.questions) {
      const a = s.answers.get(q.index);
      if (!a) continue;
      const item = items.find((x) => x.index === q.index)!;
      if (!item.skipped) {
        demoState.reviews.push({
          id: `demo-r-${q.topic_id}-${Date.now()}`,
          topic_id: q.topic_id,
          mode: q.kind === "open" ? "recall" : "quickfire",
          score: item.score,
          created_at: new Date().toISOString(),
          question: q.prompt,
          answer: item.answer ?? undefined,
          feedback: item.feedback ?? undefined,
        } as Review);
      }
    }

    const report: ReportCard = {
      session_id: sessionId,
      date: localDayKey(),
      score_pct: scorePct,
      summary:
        scorePct >= 80
          ? "Excellent session — your recall is sharp across the board. (Demo mode: add your Gemini key for real AI report cards.)"
          : scorePct >= 50
            ? "Solid session — the core ideas are there, with a few gaps worth another pass. (Demo mode: add your Gemini key for real AI report cards.)"
            : "Tough session, and that's fine — effortful recall is exactly what rewires memory. (Demo mode: add your Gemini key for real AI report cards.)",
      strengths,
      focus,
      items,
    };
    // Keep the graded report so "See report" and calendar day clicks can replay it.
    demoState.reports.push(report);
    saveDemoState();
    return report;
  }
  return api("/api/quiz", { action: "finish", sessionId, tz: tzOffsetMinutes() });
}

/**
 * Fact of the day, drawn deterministically from the facts pre-generated at
 * ingest — same fact all day, a new one tomorrow, zero AI calls.
 */
export async function getFactOfTheDay(): Promise<DailyFact | null> {
  const day = Math.floor(Date.now() / 86400000);
  if (isDemo) {
    const f = demoFacts[day % demoFacts.length];
    const topic = demoTopics.find((t) => t.id === f.topic_id);
    return { text: f.fact, topic_name: topic?.name ?? null };
  }
  const supabase = createClient();
  const { data } = await supabase.from("facts").select("fact, topics(name)").limit(300);
  const facts = (data ?? []) as unknown as Array<{ fact: string; topics: { name: string } | null }>;
  if (facts.length) {
    const f = facts[day % facts.length];
    return { text: f.fact, topic_name: f.topics?.name ?? null };
  }
  // Older accounts have no facts yet — fall back to a key point from a topic.
  const { data: topics } = await supabase.from("topics").select("name, key_points");
  const withPoints = (topics ?? []).filter((t) => (t.key_points as string[])?.length);
  if (!withPoints.length) return null;
  const t = withPoints[day % withPoints.length];
  const points = t.key_points as string[];
  return { text: points[day % points.length], topic_name: t.name };
}

export async function markPlanCompleted(): Promise<void> {
  if (isDemo) {
    if (!demoState.plan.completed) demoState.profile.streak += 1;
    demoState.plan.completed = true;
    saveDemoState();
    return;
  }
  await api("/api/plan", { action: "complete", tz: tzOffsetMinutes() });
}

export async function signOut(): Promise<void> {
  if (isDemo) return;
  const supabase = createClient();
